mapper.select:
SELECT B.RSK_FAC||A.RSK_EVT AS CD, CASE WHEN B.RSK_CATG IN ('2', '4') THEN A.RSK_EVT_NM||' ('||B.RSK_FAC_NM||')' ELSE A.RSK_EVT_NM END AS CD_NM FROM KRBA_RSK_EVT_I A , KRBA_RSK_FAC_I B WHERE 1=1 AND A.RSK_CATG = B.RSK_CATG AND A.RSK_FAC = B.RSK_FAC
AND A.RSK_CATG = #{HGRK_DTL_C , jdbcType=VARCHAR}
AND A.RSK_FAC = #{HRNK_RBA_RSK_C , jdbcType=VARCHAR}
AND A.RSK_CATG = #{HRNK_RBA_RSK_C_V , jdbcType=VARCHAR}
ORDER BY A.RSK_CATG, A.RSK_FAC, A.RSK_EVT

