MERGE INTO SRBA_DTL_C
      USING DUAL
      ON ( GRP_C = #{GRP_C, jdbcType=VARCHAR} AND DTL_C = #{DTL_C, jdbcType=VARCHAR})
      WHEN MATCHED THEN
	UPDATE SET
	       DTL_C_NM = #{DTL_C_NM, jdbcType=VARCHAR}
	      ,USYN   = #{USYN, jdbcType=VARCHAR}
	      ,SNO    = #{SNO, jdbcType=VARCHAR}
	      ,HGRK_GRP_C    = #{HGRK_GRP_C, jdbcType=VARCHAR}
	      ,HGRK_DTL_C    = #{HGRK_DTL_C, jdbcType=VARCHAR}
	      ,CHG_DT   = TO_CHAR(SYSDATE , 'YYYYMMDD')
	      ,CHG_TIME = TO_CHAR(SYSDATE , 'HH24MISS')
	      ,CHG_OP_JKW_NO = #{OP_JKW_NO, jdbcType=VARCHAR}
	WHEN NOT MATCHED THEN
	INSERT
	    ( GRP_C
	     ,DTL_C
	     ,DTL_C_NM
	     ,USYN
	     ,SNO
	     ,HGRK_GRP_C
	     ,HGRK_DTL_C
	     ,DR_DT
	     ,DR_TIME
	     ,DR_OP_JKW_NO
	     ,CHG_DT
	     ,CHG_TIME
	     ,CHG_OP_JKW_NO
	    )
	    VALUES
	    (
	      #{GRP_C,  jdbcType=VARCHAR}
	     ,#{DTL_C,  jdbcType=VARCHAR}
	     ,#{DTL_C_NM,   jdbcType=VARCHAR}
	     ,#{USYN,     jdbcType=VARCHAR}
	     ,#{SNO,  jdbcType=VARCHAR}
	     ,#{HGRK_GRP_C, jdbcType=VARCHAR}
	     ,#{HGRK_DTL_C, jdbcType=VARCHAR}
	     ,TO_CHAR(SYSDATE , 'YYYYMMDD')
	     ,TO_CHAR(SYSDATE , 'HH24MISS')
	     ,#{OP_JKW_NO,  jdbcType=VARCHAR}
	     ,TO_CHAR(SYSDATE , 'YYYYMMDD')
	     ,TO_CHAR(SYSDATE , 'HH24MISS')
	     ,#{OP_JKW_NO,  jdbcType=VARCHAR}
	    )

