mapper.select:
SELECT 0 AS SORT_ORDER ,'S0000' AS HG_RNK_DPRT_CD -- 부점구분코드 ,'전체' AS MOFC_BRNO_NM -- 부점구분명 , '99999' AS BRNO , '삼성증권' AS BRNO_NM -- 평가대상부점 , 'P00' AS CNTL_CATG1_C , '-' AS CNTL_CATG1_C_NM -- 위험분류 , 'P0000' AS CNTL_CATG2_C , '-' AS CNTL_CATG2_C_NM -- 위험분류 , 'P000000' AS CNTL_ELMN_C , '통제요소 전체' AS CNTL_ELMN_C_NM -- 위험분류
, TONGJE_VAL -- 통제효과성점수 , BF_TONGJE_VAL -- 직전 통제효과성점수 , CASE WHEN NVL(TONGJE_VAL,0) = NVL(BF_TONGJE_VAL,0) THEN '유지' WHEN NVL(TONGJE_VAL,0) > NVL(BF_TONGJE_VAL,0) THEN '상승' ELSE '하락' END AS UP_DOWN_INFO , CASE WHEN NVL(TONGJE_VAL,0) = NVL(BF_TONGJE_VAL,0) THEN '0' WHEN NVL(TONGJE_VAL,0) > NVL(BF_TONGJE_VAL,0) THEN 'R' ELSE 'B' END AS UP_DOWN_COLOR FROM (
SELECT 'S0000' AS HG_RNK_DPRT_CD -- 부점구분코드 ,'전체' AS MOFC_BRNO_NM -- 부점구분명 , '99999' AS BRNO , 'P00' AS CNTL_CATG1_C , '-' AS CNTL_CATG1_C_NM -- 위험분류 , 'P0000' AS CNTL_CATG2_C , '-' AS CNTL_CATG2_C_NM -- 위험분류 , 'P000000' AS CNTL_ELMN_C , '통제요소 전체' AS CNTL_ELMN_C_NM -- 위험분류 , ROUND(AVG(A.TONGJE_VAL),2) AS TONGJE_VAL -- 통제 효과성 점수 , ROUND(AVG(A.BF_TONGJE_VAL),2) AS BF_TONGJE_VAL -- 직전 통제 효과성 점수 FROM SRBA_V_CNTL_ELMN_SCORE A INNER JOIN NIC41B B ON A.BRNO = B.DPRT_CD WHERE A.BAS_YYMM = #{BAS_YYMM,jdbcType=VARCHAR} -- GROUP BY B.HG_RNK_DPRT_CD, A.BRNO , A.CNTL_CATG1_C
) WHERE 1=1
AND BRNO = #{BRNO, jdbcType=VARCHAR}
GROUP BY HG_RNK_DPRT_CD, BRNO , CNTL_CATG1_C , TONGJE_VAL ,BF_TONGJE_VAL UNION ALL
SELECT 1 AS SORT_ORDER , HG_RNK_DPRT_CD , MOFC_BRNO_NM , BRNO , BRNO_NM , CNTL_CATG1_C , CNTL_CATG1_C_NM -- 위험분류 , CNTL_CATG2_C , CNTL_CATG2_C_NM , CNTL_ELMN_C , CNTL_ELMN_C_NM , TONGJE_VAL -- 통제효과성점수 , BF_TONGJE_VAL -- 직전 통제효과성점수 , CASE WHEN NVL(TONGJE_VAL,0) = NVL(BF_TONGJE_VAL,0) THEN '유지' WHEN NVL(TONGJE_VAL,0) > NVL(BF_TONGJE_VAL,0) THEN '상승' ELSE '하락' END AS UP_DOWN_INFO , CASE WHEN NVL(TONGJE_VAL,0) = NVL(BF_TONGJE_VAL,0) THEN '0' WHEN NVL(TONGJE_VAL,0) > NVL(BF_TONGJE_VAL,0) THEN 'R' ELSE 'B' END AS UP_DOWN_COLOR FROM ( SELECT B.HG_RNK_DPRT_CD , CASE WHEN B.HG_RNK_DPRT_CD IS NULL THEN '전체' ELSE DECODE(B.MOFC_BRN_CCD, 'M', '본부부서', '영업점' ) END AS MOFC_BRNO_NM , BRNO , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.BRNO) AS BRNO_NM , CNTL_CATG1_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = CNTL_CATG1_C AND GRP_C = 'P001' ) AS CNTL_CATG1_C_NM -- 위험분류 , CNTL_CATG2_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = CNTL_CATG2_C AND GRP_C = 'P002' ) AS CNTL_CATG2_C_NM -- 위험분류 , CNTL_ELMN_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = CNTL_ELMN_C AND GRP_C = 'P003' ) AS CNTL_ELMN_C_NM -- 위험분류 , ROUND(AVG(A.TONGJE_VAL),2) AS TONGJE_VAL -- 통제 효과성 점수 , ROUND(AVG(A.BF_TONGJE_VAL),2) AS BF_TONGJE_VAL -- 직전 통제 효과성 점수 FROM SRBA_V_CNTL_ELMN_SCORE A INNER JOIN NIC41B B ON A.BRNO = B.DPRT_CD WHERE A.BAS_YYMM = #{BAS_YYMM,jdbcType=VARCHAR} GROUP BY B.HG_RNK_DPRT_CD, B.MOFC_BRN_CCD, A.BRNO , A.CNTL_CATG1_C , A.CNTL_CATG2_C, A.CNTL_ELMN_C ) WHERE 1=1
AND CNTL_CATG1_C = #{CNTL_CATG1_C, jdbcType=VARCHAR}
AND TONGJE_VAL > BF_TONGJE_VAL
AND TONGJE_VAL < BF_TONGJE_VAL
AND TONGJE_VAL = BF_TONGJE_VAL
AND BRNO = #{BRNO, jdbcType=VARCHAR}
ORDER BY SORT_ORDER ,BRNO, CNTL_ELMN_C ASC

SELECT A.BAS_YYYY--기준년도 , A.SNO--순번 , A.SRC_TP_C--출처유형코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R311' AND DTL_C = A.SRC_TP_C) AS SRC_TP_C_NM , A.SRC_DTL_INFO--출처상세정보 , A.ML_EXP_TITE--자금세탁사례제목 , A.ML_EXP_CTNT--자금세탁사례내용 , A.RSK_CAUS_CTNT--위험원인내용 , A.REL_NAT_NM--관련국가명 , A.REL_NAT_RSK_TP_C--관련국가위험유형코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '1' AND RSK_EVT=A.REL_NAT_RSK_TP_C) AS REL_NAT_RSK_TP_C_NM , A.CUST_DWL_TP_C--고객주거유형코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='01' AND RSK_EVT=A.CUST_DWL_TP_C) AS CUST_DWL_TP_C_NM , A.CUST_ASS_SCAL_C--고객자산규모코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='02' AND RSK_EVT=A.CUST_ASS_SCAL_C) AS CUST_ASS_SCAL_C_NM , NVL(A.CUST_OCP_G_C, '09') AS CUST_OCP_G_C --고객직업구분코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='03' AND RSK_EVT=NVL(A.CUST_OCP_G_C, '09')) AS CUST_OCP_G_C_NM , NVL(A.CUST_UPSL_G_C, '18') AS CUST_UPSL_G_C --고객업종구분코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='04' AND RSK_EVT=NVL(A.CUST_UPSL_G_C, '18')) AS CUST_UPSL_G_C_NM , NVL(A.CUST_INDV_PCUL_C, '06') AS CUST_INDV_PCUL_C --고객개인특성코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='05' AND RSK_EVT=NVL(A.CUST_INDV_PCUL_C, '06')) AS CUST_INDV_PCUL_C_NM , NVL(A.CUST_CORP_PCUL_C, '07') AS CUST_CORP_PCUL_C --고객법인특성코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='06' AND RSK_EVT=NVL(A.CUST_CORP_PCUL_C, '07')) AS CUST_CORP_PCUL_C_NM , A.CUST_RELR_TP_C--고객관련자유형코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '2' AND RSK_FAC ='07' AND RSK_EVT=A.CUST_RELR_TP_C) AS CUST_RELR_TP_C_NM , A.PROD_LN_C--상품여신코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R312' AND DTL_C =A.PROD_LN_C) AS PROD_LN_C_NM , A.PROD_INSU_C--상품보험코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R313' AND DTL_C =A.PROD_INSU_C) AS PROD_INSU_C_NM , A.PROD_INV_C--상품투자코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R314' AND DTL_C =A.PROD_INV_C) AS PROD_INV_C_NM , A.PROD_RDAMT_G_C--상품입출금구분코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R315' AND DTL_C =A.PROD_RDAMT_G_C) AS PROD_RDAMT_G_C_NM , A.PROD_TRN_SCAL--상품거래규모 , A.PROD_TRN_PCUL_C--상품거래특성코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R316' AND DTL_C =A.PROD_TRN_PCUL_C) AS PROD_TRN_PCUL_C_NM , A.ENTR_CHNL_INSU_C--가입채널보험코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '4' AND RSK_FAC ='01' AND RSK_EVT=A.ENTR_CHNL_INSU_C) AS ENTR_CHNL_INSU_C_NM , A.ENTR_CHNL_LN_C--가입채널여신코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '4' AND RSK_FAC ='02' AND RSK_EVT=A.ENTR_CHNL_LN_C) AS ENTR_CHNL_LN_C_NM , A.PAY_CHNL_C--납입채널코드 , (SELECT RSK_EVT_NM FROM KRBA_RSK_EVT_I WHERE RSK_CATG = '4' AND RSK_FAC ='03' AND RSK_EVT=A.PAY_CHNL_C) AS PAY_CHNL_C_NM , A.REL_F_CRIM_C--관련전제범죄코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R317' AND DTL_C =A.REL_F_CRIM_C) AS REL_F_CRIM_C_NM , A.REL_FNCO_C--관련금융회사코드 , A.SSPS_TRN_TP_C--의심거래유형코드 , (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE GRP_C = 'R319' AND DTL_C = A.SSPS_TRN_TP_C) AS SSPS_TRN_TP_C_NM FROM KRBA_ML_EXP_I A WHERE BAS_YYYY = #{BAS_YYMM, jdbcType=VARCHAR}
AND A.REL_F_CRIM_C = #{REL_CRIME, jdbcType=VARCHAR}
AND A.SSPS_TRN_TP_C = #{SUS_RTAN_CATE, jdbcType=VARCHAR}
AND A.SRC_TP_C = #{SRC_TP_C, jdbcType=VARCHAR}
AND A.SNO = #{SNO, jdbcType=VARCHAR}
ORDER BY A.SNO

