     , CUST_CORP_PCUL_C   /* 고객법인특성코드     */
     , CUST_RELR_TP_C     /* 고객관련자유형코드   */
     , PROD_LN_C          /* 상품여신코드         */
     , PROD_INSU_C        /* 상품보험코드         */
     , PROD_INV_C         /* 상품투자코드         */
     , PROD_RDAMT_G_C     /* 상품입출금구분코드   */
