UPDATE KRBA_RSK_EVT_M
   SET EXPS_CNT      = #{EXPS_CNT, jdbcType=NUMERIC}
     , EXPS_GD_C     = #{EXPS_GD_C, jdbcType=VARCHAR}
     , RSK_LVL_C     = #{RSK_LVL_C, jdbcType=VARCHAR}
     , CHG_DT        = TO_CHAR(SYSDATE,'YYYYMMDD')
     , CHG_TIME      = TO_CHAR(SYSDATE,'HH24MISS')
     , CHG_OP_JKW_NO = #{CHG_OP_JKW_NO, jdbcType=VARCHAR}
 WHERE BAS_YYYY      = #{BAS_YYYY, jdbcType=VARCHAR}
   AND RSK_CATG      = #{RSK_CATG, jdbcType=VARCHAR}
