SELECT * FROM ( SELECT BAS_YYMM ,VALT_BRNO ,(SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = VALT_BRNO) VALT_BRNM ,VALT01 ,VALT02 ,GYLJ_S_C /* 결재상태코드 */ ,NVL( (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R325' AND DTL_C = GYLJ_S_C) ,'미진행') AS GYLJ_S_C_NM /* 결재상태 */ ,GYLJ_ROLE_ID ,GYLJ_ID FROM( SELECT T01.BAS_YYMM AS BAS_YYMM ,T02.VALT_BRNO AS VALT_BRNO ,COUNT(T01.BAS_YYMM) AS VALT01 ,(SELECT COUNT(*) FROM SRBA_V_HRSK_R WHERE BAS_YYMM = T01.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS VALT02 ,(SELECT DISTINCT GYLJ_S_C FROM SRBA_V_HRSK_R WHERE BAS_YYMM = T01.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_S_C ,(SELECT DISTINCT GYLJ_ID FROM SRBA_V_HRSK_R WHERE BAS_YYMM = T01.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_ID ,(SELECT DISTINCT GYLJ_ROLE_ID FROM SRBA_V_HRSK_R WHERE BAS_YYMM = T01.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_ROLE_ID FROM SRBA_V_PROC_M T01 , SRBA_V_PROC_BRNO T02 , SRBA_VALT_BRNO T03 WHERE T01.BAS_YYMM = T02.BAS_YYMM AND T01.PROC_FLD_C = T02.PROC_FLD_C AND T01.PROC_FLD_C = T02.PROC_FLD_C AND T01.PROC_LGDV_C = T02.PROC_LGDV_C AND T01.PROC_MDDV_C = T02.PROC_MDDV_C AND T01.PROC_SMDV_C = T02.PROC_SMDV_C AND T01.BAS_YYMM = T03.BAS_YYMM AND T02.VALT_BRNO = T03.BRNO AND T02.BAS_YYMM = T03.BAS_YYMM
AND T01.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND T02.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
AND T01.VALT_METH_C = '2' AND T02.TGT_YN = '1' GROUP BY T01.BAS_YYMM,T02.VALT_BRNO ORDER BY T02.VALT_BRNO ) )AA WHERE 1=1
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND (AA.GYLJ_S_C IS NULL OR AA.GYLJ_S_C IN ('0','11','22'))
AND (AA.GYLJ_ROLE_ID = #{ROLE_IDS, jdbcType=VARCHAR} OR ( (AA.GYLJ_S_C IS NULL OR AA.GYLJ_S_C IN ('0','11','22')) AND AA.VALT_BRNO = #{BRCD, jdbcType=VARCHAR}))
AND AA.GYLJ_ID <> 0 AND AA.GYLJ_ROLE_ID = #{ROLE_IDS, jdbcType=VARCHAR}
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND AA.GYLJ_ID <> 0 AND AA.GYLJ_ROLE_ID = #{ROLE_IDS, jdbcType=VARCHAR}

SELECT T11.BAS_YYMM ,T11.PROC_FLD_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R303' AND DTL_C= T11.PROC_FLD_C ) AS PROC_FLD_NM ,T11.PROC_LGDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R304' AND DTL_C= T11.PROC_LGDV_C ) AS PROC_LGDV_NM ,T11.PROC_MDDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R305' AND DTL_C= T11.PROC_MDDV_C ) AS PROC_MDDV_NM ,T11.PROC_SMDV_C ,T11.PROC_SMDV_NM , T11.VALT_BRNO , (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = T11.VALT_BRNO) VALT_BRNM , T03.RSK_VALT_PNT , DECODE(RSK_VALT_PNT,'','N','Y') AS REG_YN , CASE WHEN (SELECT COUNT(ATTCH_FILE_NO) FROM RBA_ATTCH_FILE WHERE ATTCH_FILE_NO=T03.ATTCH_FILE_NO) > 0 THEN 'Y' ELSE 'N' END AS ATTATCH_YN , NVL(T03.ATTCH_FILE_NO,0) AS ATTCH_FILE_NO , T03.GYLJ_ID , T03.GYLJ_S_C , T03.GYLJ_ROLE_ID , (SELECT DISTINCT GYLJ_G_C FROM SRBA_GYLJ_H WHERE GYLJ_ID = T03.GYLJ_ID AND GYLJ_S_C = T03.GYLJ_S_C) GYLJ_G_C , (CASE WHEN T03.GYLJ_S_C IS NULL THEN 'Y' WHEN T03.GYLJ_S_C = '22' AND T03.GYLJ_ROLE_ID = (SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = (SELECT DISTINCT GYLJ_G_C FROM SRBA_GYLJ_H WHERE GYLJ_ID = T03.GYLJ_ID AND GYLJ_S_C = T03.GYLJ_S_C) AND SNO=1) THEN 'Y' ELSE 'N' END) FIRST_GYLJ_YN FROM ( SELECT T01.BAS_YYMM , T01.PROC_FLD_C , T01.PROC_LGDV_C , T01.PROC_MDDV_C , T01.PROC_SMDV_C , T01.PROC_SMDV_NM , T02.VALT_BRNO FROM SRBA_V_PROC_M T01, SRBA_V_PROC_BRNO T02 WHERE T01.BAS_YYMM = T02.BAS_YYMM AND T01.PROC_FLD_C = T02.PROC_FLD_C AND T01.PROC_FLD_C = T02.PROC_FLD_C AND T01.PROC_SMDV_C = T02.PROC_SMDV_C AND T01.PROC_LGDV_C = T02.PROC_LGDV_C AND T01.PROC_MDDV_C = T02.PROC_MDDV_C AND T01.VALT_METH_C = '2' AND T02.TGT_YN ='1' AND T01.USYN='1'
)T11 LEFT OUTER JOIN SRBA_V_HRSK_R T03 ON T11.BAS_YYMM = T03.BAS_YYMM AND T11.VALT_BRNO = T03.VALT_BRNO AND T11.PROC_FLD_C = T03.PROC_FLD_C AND T11.PROC_SMDV_C = T03.PROC_SMDV_C AND T11.PROC_LGDV_C = T03.PROC_LGDV_C AND T11.PROC_MDDV_C = T03.PROC_MDDV_C WHERE 1=1
AND T11.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND T11.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
ORDER BY PROC_SMDV_C

SELECT A.BAS_YYMM ,DECODE(#{VALT_BRNO, jdbcType=VARCHAR},'','전체',A.VALT_BRNO) AS VALT_BRNO ,A.PROC_FLD_C ,A.PROC_FLD_NM ,A.PROC_LGDV_C ,A.PROC_LGDV_NM ,A.PROC_MDDV_C ,A.PROC_MDDV_NM ,A.PROC_SMDV_C ,A.PROC_SMDV_NM ,A.RI0101 ,CASE WHEN (A.PROC_SMDV_C IN ('P020201','P020202','P020203') AND A.RI0201 = 0) THEN '' ELSE TO_CHAR(A.RI0201) END AS RI0201 ,CASE WHEN (A.PROC_SMDV_C IN ('P020101','P020102','P020103') AND A.RI0202 = 0) THEN '' ELSE TO_CHAR(A.RI0202) END AS RI0202 ,CASE WHEN (A.PROC_SMDV_C IN ('P020201','P020202','P020203') AND A.RI0203 = 0) THEN '' ELSE TO_CHAR(A.RI0203) END AS RI0203 ,CASE WHEN (A.PROC_SMDV_C IN ('P020101','P020102','P020103') AND A.RI0204 = 0) THEN '' ELSE TO_CHAR(A.RI0204) END AS RI0204 ,CASE WHEN (A.PROC_SMDV_C IN ('P020101','P020102','P020103') AND A.RI0205 = 0) THEN '' ELSE TO_CHAR(A.RI0205) END AS RI0205 ,CASE WHEN (A.PROC_SMDV_C IN ('P020201','P020202','P020203') AND A.RI0206 = 0) THEN '' ELSE TO_CHAR(A.RI0206) END AS RI0206 ,A.RI0207 ,CASE WHEN (A.PROC_SMDV_C IN ('P020201','P020202','P020203') AND A.RI0208 = 0) THEN '' ELSE TO_CHAR(A.RI0208) END AS RI0208 ,A.RI0209 ,CASE WHEN (A.PROC_SMDV_C IN ('P010101','P010103','P010201','P010701','P010801','P010802','P020101','P020102','P020103','P020201','P020202','P020203','P040101','P040103','P040201','P040203') AND A.RI0301 = 0) THEN '' ELSE TO_CHAR(A.RI0301) END AS RI0301 ,CASE WHEN (A.PROC_SMDV_C IN ('P010701','P010801','P010802','P020101','P020102','P020103','P020201','P020202','P020203','P040101','P040103','P040201','P040203') AND A.RI0302 = 0) THEN '' ELSE TO_CHAR(A.RI0302) END AS RI0302 ,CASE WHEN (A.PROC_SMDV_C IN ('P010101','P010103','P010701','P020102','P020202') AND A.RI0303 = 0) THEN '' ELSE TO_CHAR(A.RI0303) END AS RI0303 ,CASE WHEN (A.PROC_SMDV_C IN ('P010101','P010103','P010701','P020102','P020202','P040101','P040103','P040201','P040203') AND A.RI0304 = 0) THEN '' ELSE TO_CHAR(A.RI0304) END AS RI0304 ,CASE WHEN (A.PROC_SMDV_C IN ('P010101','P010102','P010103','P010201','P010701','P010702','P010709','P010801','P010802','P020101','P020102','P020103','P020201','P020202','P020203','P040101','P040103','P040201','P040203') AND A.RI0305 = 0) THEN '' ELSE TO_CHAR(A.RI0305) END AS RI0305 ,CASE WHEN (A.PROC_SMDV_C IN ('P010101','P010103','P010201','P010701','P010702','P010709','P010801','P010802','P020102','P020202','P040101','P040103','P040201','P040203') AND A.RI0306 = 0) THEN '' ELSE TO_CHAR(A.RI0306) END AS RI0306 ,CASE WHEN (A.PROC_SMDV_C IN ('P010101','P010103','P010201','P010701','P010709','P010801','P010802','P020102','P020202','P040101','P040103','P040201','P040203') AND A.RI0307 = 0) THEN '' ELSE TO_CHAR(A.RI0307) END AS RI0307 ,CASE WHEN (A.PROC_SMDV_C IN ('P010201','P010701','P010702','P010801','P010802','P020102','P020202','P040101','P040103','P040201','P040203') AND A.RI0401 = 0) THEN '' ELSE TO_CHAR(A.RI0401) END AS RI0401 ,CASE WHEN (A.PROC_SMDV_C IN ('P010101','P010102','P010103','P010201','P010701','P010702','P010801','P010802','P020102','P020202') AND A.RI0402 = 0) THEN '' ELSE TO_CHAR(A.RI0402) END AS RI0402 FROM ( SELECT T01.BAS_YYMM,T01.VALT_BRNO, T01.PROC_FLD_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R303' AND DTL_C= T01.PROC_FLD_C ) AS PROC_FLD_NM, T01.PROC_LGDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R304' AND DTL_C= T01.PROC_LGDV_C ) AS PROC_LGDV_NM, T01.PROC_MDDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R305' AND DTL_C= T01.PROC_MDDV_C ) AS PROC_MDDV_NM, T01.PROC_SMDV_C, (SELECT PROC_SMDV_NM FROM SRBA_V_PROC_M WHERE PROC_SMDV_C = T01.PROC_SMDV_C AND BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} ) AS PROC_SMDV_NM, SUM(CASE WHEN T01.RSK_INDCT = 'RI0101' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0101, SUM(CASE WHEN T01.RSK_INDCT = 'RI0201' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0201, SUM(CASE WHEN T01.RSK_INDCT = 'RI0202' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0202, SUM(CASE WHEN T01.RSK_INDCT = 'RI0203' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0203, SUM(CASE WHEN T01.RSK_INDCT = 'RI0204' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0204, SUM(CASE WHEN T01.RSK_INDCT = 'RI0205' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0205, SUM(CASE WHEN T01.RSK_INDCT = 'RI0206' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0206, SUM(CASE WHEN T01.RSK_INDCT = 'RI0207' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0207, SUM(CASE WHEN T01.RSK_INDCT = 'RI0208' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0208, SUM(CASE WHEN T01.RSK_INDCT = 'RI0209' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0209, SUM(CASE WHEN T01.RSK_INDCT = 'RI0301' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0301, SUM(CASE WHEN T01.RSK_INDCT = 'RI0302' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0302, SUM(CASE WHEN T01.RSK_INDCT = 'RI0303' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0303, SUM(CASE WHEN T01.RSK_INDCT = 'RI0304' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0304, SUM(CASE WHEN T01.RSK_INDCT = 'RI0305' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0305, SUM(CASE WHEN T01.RSK_INDCT = 'RI0306' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0306, SUM(CASE WHEN T01.RSK_INDCT = 'RI0307' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0307, SUM(CASE WHEN T01.RSK_INDCT = 'RI0401' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0401, SUM(CASE WHEN T01.RSK_INDCT = 'RI0402' THEN TO_CHAR(T01.RSK_VALT_PNT) ELSE '0' END) AS RI0402 FROM SRBA_V_RSK_R T01, SRBA_VALT_BRNO C WHERE 1=1 AND T01.BAS_YYMM = C.BAS_YYMM AND T01.VALT_BRNO = C.BRNO
AND T01.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
