GROUP BY T01.BAS_YYMM,T01.VALT_BRNO,T01.PROC_FLD_C, T01.PROC_LGDV_C , T01.PROC_MDDV_C,T01.PROC_SMDV_C ) A

SELECT T01.VALT_BRNO, (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = T01.VALT_BRNO) AS VALT_BRNM , T01.VALT_PNT AS RSK_VALT_PNT, T01.VALT_RSK_RANK AS RANK FROM SRBA_V_RSK_RANK_R T01, SRBA_VALT_BRNO C WHERE 1=1 AND T01.BAS_YYMM = C.BAS_YYMM AND T01.VALT_BRNO = C.BRNO
