)

	UPDATE SRBA_V_HRSK_R
	   SET
          RSK_VALT_PNT 	= #{RSK_VALT_PNT,jdbcType=VARCHAR},
	   	  DR_DT             = TO_CHAR(SYSDATE,'YYYYMMDD'),
		  DR_TIME           = TO_CHAR(SYSDATE,'HH24MISS'),
		  DR_OP_JKW_NO      = #{DR_OP_JKW_NO, jdbcType=VARCHAR}
	WHERE BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
	AND   PROC_FLD_C = #{PROC_FLD_C,jdbcType=VARCHAR}
	AND   PROC_LGDV_C = #{PROC_LGDV_C,jdbcType=VARCHAR}
	AND   PROC_MDDV_C = #{PROC_MDDV_C,jdbcType=VARCHAR}
	AND   PROC_SMDV_C = #{PROC_SMDV_C,jdbcType=VARCHAR}
	AND   VALT_BRNO =   #{VALT_BRNO,jdbcType=VARCHAR}

        MERGE INTO SRBA_V_HRSK_R
			USING DUAL
		  ON (BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND PROC_FLD_C = #{PROC_FLD_C, jdbcType=VARCHAR}
            AND PROC_LGDV_C = #{PROC_LGDV_C, jdbcType=VARCHAR} AND PROC_MDDV_C = #{PROC_MDDV_C, jdbcType=VARCHAR}
            AND PROC_SMDV_C = #{PROC_SMDV_C, jdbcType=VARCHAR} AND VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}

            )
		WHEN MATCHED THEN
		UPDATE SET
           RSK_VALT_PNT 	= #{RSK_VALT_PNT,jdbcType=VARCHAR},
           DR_DT             = TO_CHAR(SYSDATE,'YYYYMMDD'),
           DR_TIME           = TO_CHAR(SYSDATE,'HH24MISS'),
           DR_OP_JKW_NO      = #{DR_OP_JKW_NO, jdbcType=VARCHAR},
           ATTCH_FILE_NO      = #{ATTCH_FILE_NO, jdbcType=VARCHAR}

		WHEN NOT MATCHED THEN
		INSERT (
            BAS_YYMM
            ,PROC_FLD_C
            ,PROC_LGDV_C
            ,PROC_MDDV_C
            ,PROC_SMDV_C
            ,VALT_BRNO
            ,RSK_VALT_PNT
            ,DR_DT
            ,DR_TIME
            ,DR_OP_JKW_NO
            ,ATTCH_FILE_NO

		)
		VALUES
		(
            #{BAS_YYMM,jdbcType=VARCHAR}
            ,#{PROC_FLD_C,jdbcType=VARCHAR}
            ,#{PROC_LGDV_C,jdbcType=VARCHAR}
            ,#{PROC_MDDV_C,jdbcType=VARCHAR}
            ,#{PROC_SMDV_C,jdbcType=VARCHAR}
            ,#{VALT_BRNO,jdbcType=VARCHAR}
            ,0
            ,TO_CHAR(SYSDATE,'YYYYMMDD')
            ,TO_CHAR(SYSDATE,'HH24MISS')
            ,#{DR_OP_JKW_NO, jdbcType=VARCHAR}
            ,#{ATTCH_FILE_NO, jdbcType=VARCHAR}
		)

    DELETE FROM SRBA_V_HRSK_R
	 WHERE BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
	   AND   PROC_FLD_C = #{PROC_FLD_C,jdbcType=VARCHAR}
