SELECT AAA.* ,(SELECT CD_NM FROM NIC92B WHERE CD='M034' AND CNTNT =AAA.GDS_NO) AS GDS_CD_NM ,(SELECT CD_NM FROM NIC92B WHERE CD='M044' AND CNTNT =AAA.DL_CHNNL_CD) AS DL_CHNNL_CD_NM ,(SELECT CD_NM FROM NIC92B WHERE CD='M045' AND CNTNT =AAA.DL_TYP_CD) AS DL_TYP_CD_NM ,(SELECT CD_NM FROM NIC92B WHERE CD='M046' AND CNTNT =AAA.DL_WY_CD) AS DL_WY_CD_NM , TO_CHAR(DL_AMT, 'FM999,999,999,999') AS DL_AMT , TO_CHAR(DL_AMT, 'FM999,999,999,999') AS CSH_AMT , TO_CHAR(DL_AMT, 'FM999,999,999,999') AS CHCK_AMT FROM ( SELECT ROWNUM AS NUM , AA.* FROM ( SELECT A.VALT_YYMM , A.PROC_FLD_C , A.PROC_LGDV_C , A.PROC_MDDV_C , A.PROC_SMDV_C , A.RSK_CATG , A.RSK_FAC , A.RSK_INDCT , A.VALT_BRNO , A.GNL_AC_NO , A.GDS_NO , B.GDS_CD , A.DL_DT , A.DL_SQ , B.AML_CUST_ID , C.I_AMT_P_RNM_NO , DL_CCD , DL_CHNNL_CD , DL_MD_CCD , DL_TYP_CD , DL_WY_CD , C.SMRY_TYP_CD , '' AS SMRY_TYP_NM , DL_AMT , CSH_AMT, CHCK_AMT , C.DR_DT , C.DR_TIME FROM SRBA_V_MM_TRN_I A, NIC17B B, SRBA_TRN_I C WHERE 1=1 AND A.GNL_AC_NO=B.GNL_AC_NO AND A.GDS_NO=B.GDS_NO AND A.VALT_YYMM = C.VALT_YYMM AND A.GNL_AC_NO = C.GNL_AC_NO AND A.VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
AND A.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
AND A.PROC_LGDV_C = #{PROC_LGDV_C, jdbcType=VARCHAR} AND A.PROC_MDDV_C = #{PROC_MDDV_C, jdbcType=VARCHAR} AND A.PROC_SMDV_C = #{PROC_SMDV_C, jdbcType=VARCHAR} AND A.RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR} AND A.RSK_FAC = #{RSK_FAC, jdbcType=VARCHAR} AND A.RSK_INDCT = #{RSK_INDCT, jdbcType=VARCHAR} AND A.DL_DT = C.DL_DT ORDER BY DL_DT ) AA ) AAA WHERE AAA.NUM BETWEEN #{stRowNum, jdbcType=VARCHAR} AND #{edRowNum, jdbcType=VARCHAR}

