SELECT AAA.* ,(SELECT CD_NM FROM NIC92B WHERE CD='M004' AND CNTNT =AAA.NTN_CD) AS NTN_CD_NM , DECODE(AAA.INDV_CORP_CCD,'1','개인','법인') AS INDV_CORP_CCD_NM ,(SELECT CD_NM FROM NIC92B WHERE CD='M008' AND CNTNT =AAA.INDST_RSK_DVD_CD) AS INDST_RSK_DVD_CD_NM ,(SELECT CD_NM FROM NIC92B WHERE CD='S004' AND CNTNT =AAA.JOB_C) AS JOB_C_NM FROM ( SELECT ROWNUM AS NUM , AA.* FROM ( SELECT T11.VALT_YYMM , T11.PROC_FLD_C , T11.PROC_LGDV_C , T11.PROC_MDDV_C , T11.PROC_SMDV_C , T11.RSK_CATG , T11.RSK_FAC , T11.RSK_INDCT , T11.VALT_BRNO , T11.AML_CUST_ID , T12.CS_NM , T12.UNAGE_YN , T12.NTN_CD , T12.INDV_CORP_CCD , T12.INDST_RSK_DVD_CD , T12.JOB_C , T12.PEP_YN , T12.LG_AMT_ASTS_YN , T12.NPRFT_GROUP_YN , NVL(T12.LSTNG_YN,'N/A') AS LSTNG_YN , T12.NFR_DIT_YN , T12.RSDNC_YN , T12.NEW_CUST_YN , T12.UN_TRN_YN , T12.STR_YN , T12.BTYMD FROM SRBA_V_MM_CUST_I T11, SRBA_CUST_I T12 WHERE T11.VALT_YYMM = T12.VALT_YYMM AND T11.AML_CUST_ID = T12.AML_CUST_ID AND T11.VALT_YYMM = #{VALT_YYMM, jdbcType=VARCHAR}
AND T11.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
AND T11.PROC_LGDV_C = #{PROC_LGDV_C, jdbcType=VARCHAR} AND T11.PROC_MDDV_C = #{PROC_MDDV_C, jdbcType=VARCHAR} AND T11.PROC_SMDV_C = #{PROC_SMDV_C, jdbcType=VARCHAR} AND T11.RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR} AND T11.RSK_FAC = #{RSK_FAC, jdbcType=VARCHAR} AND T11.RSK_INDCT = #{RSK_INDCT, jdbcType=VARCHAR} ) AA ) AAA WHERE 1=1
AND AAA.NUM BETWEEN #{stRowNum, jdbcType=VARCHAR} AND #{edRowNum, jdbcType=VARCHAR}

SELECT AA.* FROM ( SELECT BAS_YYMM ,VALT_BRNO , (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = VALT_BRNO) VALT_BRNM ,VALT01 ,VALT02 ,VALT03 ,(CASE WHEN VALT01 = VALT02 AND VALT01 = VALT03 THEN 'Y' ELSE 'N' END ) AS VALT04 ,GYLJ_S_C /* 결재상태코드 */ ,NVL( (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R325' AND DTL_C = GYLJ_S_C) ,'미진행') AS GYLJ_S_C_NM /* 결재상태 */ ,GYLJ_ROLE_ID ,GYLJ_ID FROM( SELECT T02.BAS_YYMM AS BAS_YYMM ,T02.VALT_BRNO AS VALT_BRNO ,COUNT(T02.BAS_YYMM) AS VALT01 ,(SELECT COUNT(*) FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO AND DSGN_VALT_PNT IS NOT NULL) AS VALT02 ,(SELECT COUNT(*) FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO AND TONGJE_VALD_PNT IS NOT NULL) AS VALT03 ,(SELECT DISTINCT GYLJ_S_C FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_S_C ,(SELECT DISTINCT GYLJ_ID FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_ID ,(SELECT DISTINCT GYLJ_ROLE_ID FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS GYLJ_ROLE_ID FROM SRBA_V_TONGJE_R T02, SRBA_VALT_BRNO C WHERE 1=1 AND T02.BAS_YYMM = C.BAS_YYMM AND T02.VALT_BRNO = C.BRNO
AND T02.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND T02.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
GROUP BY T02.BAS_YYMM,T02.VALT_BRNO ) )AA WHERE 1=1
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND (AA.GYLJ_S_C IS NULL OR AA.GYLJ_S_C IN ('0','11','22'))
AND (AA.GYLJ_ROLE_ID = #{ROLE_IDS, jdbcType=VARCHAR} OR ( (AA.GYLJ_S_C IS NULL OR AA.GYLJ_S_C IN ('0','11','22')) AND AA.VALT_BRNO = #{BRCD, jdbcType=VARCHAR}))
AND AA.GYLJ_ID <> 0 AND AA.GYLJ_ROLE_ID = #{ROLE_IDS, jdbcType=VARCHAR}
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND AA.GYLJ_ID <> 0 AND AA.GYLJ_ROLE_ID = #{ROLE_IDS, jdbcType=VARCHAR}

SELECT T03.BAS_YYMM ,T03.PROC_LGDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R312' AND DTL_C= T03.PROC_LGDV_C ) AS PROC_LGDV_NM ,T03.PROC_MDDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R313' AND DTL_C= T03.PROC_MDDV_C ) AS PROC_MDDV_NM ,T03.PROC_SMDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R314' AND DTL_C= T03.PROC_SMDV_C ) AS PROC_SMDV_NM , T03.TONGJE_NO , (SELECT TONGJE_ACT_TITE FROM SRBA_V_TONGJE_M WHERE TONGJE_NO = T03.TONGJE_NO AND BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}) AS TONGJE_ACT_TITE , DECODE(T03.DSGN_VALT_PNT,'','입력',T03.DSGN_VALT_PNT) AS DSGN_VALT_PNT , DECODE(T03.TONGJE_VALD_PNT,'','입력',T03.TONGJE_VALD_PNT) AS TONGJE_VALD_PNT , T03.VALT_BRNO , (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = T03.VALT_BRNO) VALT_BRNM , CASE WHEN DSGN_VALT_PNT IS NOT NULL AND TONGJE_VALD_PNT IS NOT NULL THEN 'Y' ELSE 'N' END AS COMPLETE_YN , T03.GYLJ_ID , T03.GYLJ_S_C , T03.GYLJ_ROLE_ID , (SELECT DISTINCT GYLJ_G_C FROM SRBA_GYLJ_H WHERE GYLJ_ID = T03.GYLJ_ID AND GYLJ_S_C = T03.GYLJ_S_C) GYLJ_G_C , (CASE WHEN T03.GYLJ_S_C IS NULL THEN 'Y' WHEN T03.GYLJ_S_C = '22' AND T03.GYLJ_ROLE_ID = (SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = (SELECT DISTINCT GYLJ_G_C FROM SRBA_GYLJ_H WHERE GYLJ_ID = T03.GYLJ_ID AND GYLJ_S_C = T03.GYLJ_S_C) AND SNO=1) THEN 'Y' ELSE 'N' END) FIRST_GYLJ_YN FROM SRBA_V_TONGJE_R T03 WHERE 1=1
AND T03.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND T03.VALD_VALT_METH_C = #{VALD_VALT_METH_C, jdbcType=VARCHAR}
AND T03.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
ORDER BY PROC_SMDV_C

