WITH BAS_LST AS (
SELECT ( SELECT BAS_YYMM FROM ( SELECT ROWNUM AS NUM, BAS_YYMM FROM ( SELECT BAS_YYMM FROM SRBA_VALT_SCHD_M WHERE BAS_YYMM != '999912' AND BAS_YYMM <= #{BAS_YYMM, jdbcType=VARCHAR} ORDER BY BAS_YYMM DESC )WHERE 1=1 AND ROWNUM < 4 ) WHERE NUM = 3 ) AS N_YYMM ,( SELECT BAS_YYMM FROM ( SELECT ROWNUM AS NUM, BAS_YYMM FROM ( SELECT BAS_YYMM FROM SRBA_VALT_SCHD_M WHERE BAS_YYMM != '999912' AND BAS_YYMM <= #{BAS_YYMM, jdbcType=VARCHAR} ORDER BY BAS_YYMM DESC )WHERE 1=1 AND ROWNUM < 4 ) WHERE NUM = 2 ) AS O_YYMM ,( SELECT BAS_YYMM FROM ( SELECT ROWNUM AS NUM, BAS_YYMM FROM ( SELECT BAS_YYMM FROM SRBA_VALT_SCHD_M WHERE BAS_YYMM != '999912' AND BAS_YYMM <= #{BAS_YYMM, jdbcType=VARCHAR} ORDER BY BAS_YYMM DESC )WHERE 1=1 AND ROWNUM < 4 ) WHERE NUM = 1 )AS C_YYMM FROM DUAL
) SELECT T21.BAS_YYMM ,T21.TONGJE_FLD_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R312' AND DTL_C= T21.TONGJE_FLD_C ) AS TONGJE_FLD_NM ,T21.TONGJE_LGDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R313' AND DTL_C= T21.TONGJE_LGDV_C ) AS TONGJE_LGDV_NM ,T21.TONGJE_MDDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R314' AND DTL_C= T21.TONGJE_MDDV_C ) AS TONGJE_MDDV_NM ,T21.TONGJE_SMDV_C ,T21.TONGJE_SMDV_NM , T21.VALT_BRNO , T21.TONGJE_VALT_PNT AS TONGJE_VALT_PNT1 , T21.TONGJE_VALT_RT AS TONGJE_VALT_RT1 , T22.TONGJE_VALT_PNT AS TONGJE_VALT_PNT2 , T22.TONGJE_VALT_RT AS TONGJE_VALT_RT2 , T23.TONGJE_VALT_PNT AS TONGJE_VALT_PNT3 , T23.TONGJE_VALT_RT AS TONGJE_VALT_RT3 , (SELECT N_YYMM FROM BAS_LST) AS N_YYMM , (SELECT O_YYMM FROM BAS_LST) AS O_YYMM , (SELECT C_YYMM FROM BAS_LST) AS C_YYMM FROM ( SELECT T11.BAS_YYMM , T11.TONGJE_FLD_C , T11.TONGJE_LGDV_C , T11.TONGJE_MDDV_C , T11.TONGJE_SMDV_C , T11.TONGJE_SMDV_NM , T11.VALT_BRNO , T11.TONGJE_VALT_PNT , T11.TONGJE_VALT_RT FROM ( SELECT T01.BAS_YYMM , T01.TONGJE_FLD_C , T01.TONGJE_LGDV_C , T01.TONGJE_MDDV_C , T01.TONGJE_SMDV_C ,(SELECT TONGJE_SMDV_NM FROM SRBA_V_TONGJE_M WHERE TONGJE_SMDV_C = T01.TONGJE_SMDV_C AND BAS_YYMM = (SELECT C_YYMM FROM BAS_LST) ) AS TONGJE_SMDV_NM , T01.VALT_BRNO , T01.TONGJE_VALT_PNT , T01.TONGJE_VALT_RT FROM SRBA_V_TONGJE_R T01 WHERE 1=1 AND T01.BAS_YYMM = (SELECT C_YYMM FROM BAS_LST) ) T11 )T21 LEFT OUTER JOIN ( SELECT T11.BAS_YYMM , T11.TONGJE_FLD_C , T11.TONGJE_LGDV_C , T11.TONGJE_MDDV_C , T11.TONGJE_SMDV_C , T11.TONGJE_SMDV_NM , T11.VALT_BRNO , T11.TONGJE_VALT_PNT , T11.TONGJE_VALT_RT FROM (
SELECT T01.BAS_YYMM , T01.TONGJE_FLD_C , T01.TONGJE_LGDV_C , T01.TONGJE_MDDV_C , T01.TONGJE_SMDV_C ,(SELECT TONGJE_SMDV_NM FROM SRBA_V_TONGJE_M WHERE TONGJE_SMDV_C = T01.TONGJE_SMDV_C AND BAS_YYMM = (SELECT O_YYMM FROM BAS_LST) ) AS TONGJE_SMDV_NM , T01.VALT_BRNO , T01.TONGJE_VALT_PNT , T01.TONGJE_VALT_RT FROM SRBA_V_TONGJE_R T01 WHERE 1=1 AND T01.BAS_YYMM = (SELECT O_YYMM FROM BAS_LST) ) T11 )T22 ON T21.VALT_BRNO = T22.VALT_BRNO AND T21.TONGJE_FLD_C = T22.TONGJE_FLD_C AND T21.TONGJE_LGDV_C= T22.TONGJE_LGDV_C AND T21.TONGJE_MDDV_C= T22.TONGJE_MDDV_C AND T21.TONGJE_SMDV_C= T22.TONGJE_SMDV_C LEFT OUTER JOIN ( SELECT T11.BAS_YYMM , T11.TONGJE_FLD_C , T11.TONGJE_LGDV_C , T11.TONGJE_MDDV_C , T11.TONGJE_SMDV_C , T11.TONGJE_SMDV_NM , T11.VALT_BRNO , T11.TONGJE_VALT_PNT , T11.TONGJE_VALT_RT FROM ( SELECT T01.BAS_YYMM , T01.TONGJE_FLD_C , T01.TONGJE_LGDV_C , T01.TONGJE_MDDV_C , T01.TONGJE_SMDV_C ,(SELECT TONGJE_SMDV_NM FROM SRBA_V_TONGJE_M WHERE TONGJE_SMDV_C = T01.TONGJE_SMDV_C AND BAS_YYMM = (SELECT N_YYMM FROM BAS_LST) ) AS TONGJE_SMDV_NM , T01.VALT_BRNO , T01.TONGJE_VALT_PNT , T01.TONGJE_VALT_RT FROM SRBA_V_TONGJE_R T01 WHERE 1=1 AND T01.BAS_YYMM = (SELECT N_YYMM FROM BAS_LST) ) T11 )T23 ON T21.VALT_BRNO = T23.VALT_BRNO AND T21.TONGJE_FLD_C = T23.TONGJE_FLD_C AND T21.TONGJE_LGDV_C= T23.TONGJE_LGDV_C AND T21.TONGJE_MDDV_C= T23.TONGJE_MDDV_C AND T21.TONGJE_SMDV_C= T23.TONGJE_SMDV_C WHERE 1=1
AND T21.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}

SELECT BAS_YYMM ,VALT_BRNO ,(SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = VALT_BRNO) VALT_BRNM ,VALT01 ,VALT02 ,VALT03 ,(CASE WHEN VALT01 = VALT02 AND VALT01 = VALT03 THEN 'Y' ELSE 'N' END ) AS VALT04 FROM( SELECT T02.BAS_YYMM AS BAS_YYMM ,T02.VALT_BRNO AS VALT_BRNO ,COUNT(T02.BAS_YYMM) AS VALT01 ,(SELECT COUNT(*) FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO AND DSGN_VALT_PNT IS NOT NULL) AS VALT02 ,(SELECT COUNT(*) FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO AND TONGJE_VALD_PNT IS NOT NULL) AS VALT03 FROM SRBA_V_TONGJE_R T02, SRBA_VALT_BRNO C WHERE 1=1 AND T02.BAS_YYMM = C.BAS_YYMM AND T02.VALT_BRNO = C.BRNO
AND T02.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND T02.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
GROUP BY T02.BAS_YYMM,T02.VALT_BRNO )

SELECT BAS_YYMM ,VALT_BRNO ,(SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = VALT_BRNO) VALT_BRNM ,VALT01 ,VALT02 ,VALT03 ,(CASE WHEN VALT01 = VALT02 AND VALT01 = VALT03 THEN 'Y' ELSE 'N' END ) AS VALT04 FROM( SELECT T02.BAS_YYMM AS BAS_YYMM ,T02.VALT_BRNO AS VALT_BRNO ,COUNT(T02.BAS_YYMM) AS VALT01 ,(SELECT COUNT(*) FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO AND DSGN_VALT_PNT IS NOT NULL) AS VALT02 ,(SELECT COUNT(*) FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO AND TONGJE_VALD_PNT IS NOT NULL) AS VALT03 FROM SRBA_V_TONGJE_R T02, SRBA_VALT_BRNO C WHERE 1=1 AND T02.BAS_YYMM = C.BAS_YYMM AND T02.VALT_BRNO = C.BRNO
AND T02.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND T02.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
GROUP BY T02.BAS_YYMM,T02.VALT_BRNO )

SELECT A.BAS_YYMM, A.PROC_FLD_C AS TONGJE_FLD_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R303' AND DTL_C= A.PROC_FLD_C ) AS TONGJE_FLD_NM , A.PROC_LGDV_C AS TONGJE_LGDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R312' AND DTL_C= A.PROC_LGDV_C ) AS TONGJE_LGDV_NM , A.PROC_MDDV_C AS TONGJE_MDDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R313' AND DTL_C= A.PROC_MDDV_C ) AS TONGJE_MDDV_NM , A.PROC_SMDV_C AS TONGJE_SMDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R314' AND DTL_C= A.PROC_SMDV_C ) AS TONGJE_SMDV_NM , A.TONGJE_NO, A.TONGJE_ACT_TITE, A.TONGJE_ISP_STEP, /*통제지표절차*/
A.DSGN_VALT_PROF, /*설계평가증빙자료*/ A.DSGN_VALT_TP_C, /*설계평가유형코드*/ (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R328' AND DTL_C= A.DSGN_VALT_TP_C ) AS DSGN_VALT_TP_NM , A.VALD_VALT_METH_C, /*운영평가 방법*/ (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R329' AND DTL_C= A.VALD_VALT_METH_C ) AS VALD_VALT_METH_NM , A.VALT_METH_C, /*운영평가 유형*/ (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R330' AND DTL_C= A.VALT_METH_C ) AS VALT_METH_NM , A.OPR_VALT_JIPYO_NM, /*운영평가 지표명*/ A.TONGJE_SCOR_OFFR_C, /*운영평가값 산정기준*/ (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R331' AND DTL_C= A.TONGJE_SCOR_OFFR_C ) AS TONGJE_SCOR_OFFR_NM ,
B.VALT_BRNO, DECODE(VALT_BRNO,'9999','지점전체',DPRT_NM) AS DPRT_NM, B.DSGN_VALT_PNT, B.TONGJE_VALD_PNT, DECODE(B.DSGN_VALT_PNT,'','미완료',B.DSGN_VALT_PNT) AS DESIGN_VALUE, DECODE(B.TONGJE_VALD_PNT,'','미완료',B.TONGJE_VALD_PNT) AS OPERATION_VALUE, A.ATTCH_FILE_NO AS ATTCH_FILE_NO, B.ATTCH_FILE_NO AS ATTCH_FILE_NO_R FROM SRBA_V_TONGJE_M A, SRBA_V_TONGJE_R B, NIC41B C WHERE A.BAS_YYMM= B.BAS_YYMM(+) AND A.PROC_FLD_C = B.PROC_FLD_C (+) AND A.PROC_LGDV_C = B.PROC_LGDV_C(+) AND A.PROC_MDDV_C= B.PROC_MDDV_C(+) AND A.PROC_SMDV_C = B.PROC_SMDV_C(+) AND A.TONGJE_NO = B.TONGJE_NO(+) AND B.VALT_BRNO = C.DPRT_CD(+) AND A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND A.PROC_LGDV_C = #{TONGJE_LGDV_C, jdbcType=VARCHAR}
AND A.PROC_MDDV_C = #{TONGJE_MDDV_C, jdbcType=VARCHAR}
AND A.PROC_SMDV_C = #{TONGJE_SMDV_C, jdbcType=VARCHAR}
AND A.TONGJE_NO = #{TONGJE_NO, jdbcType=VARCHAR}
AND VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}

