SELECT F.BAS_YYMM , F.BRNO , CASE WHEN BR.HG_RNK_DPRT_CD IS NULL THEN '삼성증권' ELSE (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = BR.HG_RNK_DPRT_CD) END AS HGRK_BRNO_NM , CASE WHEN BR.HG_RNK_DPRT_CD IS NULL THEN '전체' ELSE DECODE(BR.MOFC_BRN_CCD, 'M', '본부부서', '영업점' ) END AS MOFC_BRNO_NM , CASE WHEN BR.HG_RNK_DPRT_CD IS NULL THEN '삼성증권' ELSE BR.DPRT_NM END AS BRNO_NM , A.REMDR_RSK_GD_C , F.FINAL_VAL || '(' || F.FINAL_UP_DOWN || ')' AS FINAL_VAL , F.RISK_VAL || '(' || F.RISK_UP_DOWN || ')' AS RISK_VAL , F.TONGJE_VAL || '(' || F.TONGJE_UP_DOWN || ')' AS TONGJE_VAL , B.REMDR_RSK_GD_C AS BF_REMDR_RSK_GD_C , F.BF_FINAL_VAL , F.BF_RISK_VAL , F.BF_TONGJE_VAL , CASE WHEN F.FINAL_UP_DOWN = '▼' THEN '하락(▼)' WHEN F.FINAL_UP_DOWN = '▲' THEN '상승(▲)' ELSE '유지(-)' END AS CHANGE_GUBUN FROM SRBA_FINAL_EVAL F LEFT JOIN SRBA_REMDR_RSK_I A ON F.FINAL_VAL >= A.GD_S_SECT AND F.FINAL_VAL < A.GD_E_SECT LEFT JOIN SRBA_REMDR_RSK_I B ON F.BF_FINAL_VAL >= B.GD_S_SECT AND F.BF_FINAL_VAL < B.GD_E_SECT LEFT JOIN NIC41B BR ON BR.DPRT_CD = F.BRNO WHERE F.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND F.BRNO = #{BRNO, jdbcType=VARCHAR}
AND F.FINAL_UP_DOWN = #{FINAL_UP_DOWN,jdbcType=VARCHAR}
AND F.RISK_UP_DOWN = #{RISK_UP_DOWN,jdbcType=VARCHAR}
AND F.TONGJE_UP_DOWN = #{TONGJE_UP_DOWN,jdbcType=VARCHAR}
AND F.FINAL_UP_DOWN = '▲'
AND F.FINAL_UP_DOWN = '▼'
AND F.FINAL_UP_DOWN = '-'
ORDER BY BR.MOFC_BRN_CCD DESC , F.BRNO

SELECT BAS_YYMM, PROC_LGDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R304' AND DTL_C= PROC_LGDV_C ) AS PROC_LGDV_NM , PROC_MDDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R305' AND DTL_C= PROC_MDDV_C ) AS PROC_MDDV_NM , PROC_SMDV_C , (SELECT PROC_SMDV_NM FROM SRBA_V_PROC_M WHERE PROC_SMDV_C = A. PROC_SMDV_C AND BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} ) AS PROC_SMDV_NM , RSK_VALT_PNT, TONGJE_VALT_PNT, REMDR_RSK_PNT, REMDR_RSK_GD_C, VALT_BRNO FROM SRBA_V_REMDR_R A WHERE 1=1
AND BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}

SELECT T01.BAS_YYMM , T01.PROC_FLD_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R303' AND DTL_C= T01.PROC_FLD_C ) AS PROC_FLD_NM ,T01.PROC_LGDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R304' AND DTL_C= T01.PROC_LGDV_C ) AS PROC_LGDV_NM ,T01.PROC_MDDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R305' AND DTL_C= T01.PROC_MDDV_C ) AS PROC_MDDV_NM , T01.PROC_SMDV_C ,(SELECT PROC_SMDV_NM FROM SRBA_V_PROC_M WHERE PROC_SMDV_C = T01.PROC_SMDV_C AND BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} ) AS PROC_SMDV_NM , T01.VALT_BRNO , (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = T01.VALT_BRNO ) As VALT_BRNM , T01.REMDR_RSK_PNT , DECODE(T01.REMDR_RSK_GD_C,'R','Red','Y','Yellow','G','Green') AS REMDR_RSK_GD_C FROM SRBA_V_REMDR_R T01 WHERE 1=1
AND T01.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND T01.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
AND T01.PROC_LGDV_C = #{PROC_LGDV_C, jdbcType=VARCHAR}
AND T01.PROC_MDDV_C = #{PROC_MDDV_C, jdbcType=VARCHAR}
AND T01.PROC_SMDV_C = #{PROC_SMDV_C, jdbcType=VARCHAR}
ORDER BY T01.PROC_FLD_C, T01.PROC_LGDV_C, T01.PROC_MDDV_C, T01.PROC_SMDV_C,T01.VALT_BRNO

SELECT BAS_YYMM , SNO , GD_S_SECT , SGD_G_C , GD_E_SECT , EGD_G_C , REMDR_RSK_GD_C , TOP_ACUM_PER , DR_DT , DR_TIME , DR_OP_JKW_NO , CHG_DT , CHG_TIME , CHG_OP_JKW_NO FROM SRBA_REMDR_RSK_I WHERE 1=1
