mapper.select:
SELECT ROWNUM , T03.* FROM ( SELECT AA.BAS_YYMM ,AA.BRNO , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = AA.BRNO) VALT_BRNM ,NVL(VALT01,0) AS VALT01 ,NVL(VALT02,0) AS VALT02 ,NVL((VALT01 - VALT02),0) AS VALT03 ,CASE WHEN (VALT01 - VALT02 = 0 ) THEN '완료' WHEN (VALT01 - VALT02 > 0 ) THEN '미완료' ELSE '대상아님' END VALT04 ,NVL(VALT11,0) AS VALT11 ,NVL(VALT12,0) AS VALT12 ,NVL((VALT11 - VALT12),0) AS VALT13 ,CASE WHEN (VALT11 - VALT12 = 0 ) THEN '완료' WHEN (VALT11 - VALT12 > 0 ) THEN '미완료' ELSE '대상아님' END VALT14 ,NVL(VALT21,0) AS VALT21 ,NVL(VALT22,0) AS VALT22 ,NVL((VALT21 - VALT22),0) AS VALT23 ,CASE WHEN (VALT21 - VALT22 = 0 ) THEN '완료' WHEN (VALT21 - VALT22 > 0 ) THEN '미완료' ELSE '대상아님' END VALT24 , '전송' AS MAIL_SEND FROM SRBA_VALT_BRNO AA LEFT OUTER JOIN ( SELECT T01.BAS_YYMM AS BAS_YYMM ,T02.VALT_BRNO AS VALT_BRNO ,COUNT(T01.BAS_YYMM) AS VALT01 ,(SELECT COUNT(*) FROM SRBA_V_HRSK_R WHERE BAS_YYMM = T01.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO) AS VALT02 FROM SRBA_V_PROC_M T01 , SRBA_V_PROC_BRNO T02 WHERE T01.BAS_YYMM = T02.BAS_YYMM AND T01.PROC_FLD_C = T02.PROC_FLD_C AND T01.PROC_FLD_C = T02.PROC_FLD_C AND T01.PROC_LGDV_C = T02.PROC_LGDV_C AND T01.PROC_MDDV_C = T02.PROC_MDDV_C AND T01.PROC_SMDV_C = T02.PROC_SMDV_C AND T01.VALT_METH_C = '2' AND T01.USYN = '1' AND T02.TGT_YN = '1' GROUP BY T01.BAS_YYMM,T02.VALT_BRNO ) BB ON AA.BRNO = BB.VALT_BRNO AND AA.BAS_YYMM = BB.BAS_YYMM LEFT OUTER JOIN ( SELECT BAS_YYMM ,VALT_BRNO ,VALT01 AS VALT11 ,VALT02 AS VALT12 FROM( SELECT T02.BAS_YYMM AS BAS_YYMM ,T02.VALT_BRNO AS VALT_BRNO ,COUNT(T02.BAS_YYMM) AS VALT01 ,(SELECT COUNT(*) FROM SRBA_V_TONGJE_R WHERE BAS_YYMM = T02.BAS_YYMM AND VALT_BRNO = T02.VALT_BRNO AND TONGJE_VALD_PNT IS NOT NULL) AS VALT02 FROM SRBA_V_TONGJE_R T02 WHERE 1=1 GROUP BY T02.BAS_YYMM,T02.VALT_BRNO ) ) CC ON AA.BRNO = CC.VALT_BRNO AND AA.BAS_YYMM = CC.BAS_YYMM LEFT OUTER JOIN ( SELECT A.BAS_YYMM ,A.VALT_BRNO ,(SELECT COUNT(VALT_BRNO) FROM SRBA_V_REMDR_R C WHERE C.BAS_YYMM = A.BAS_YYMM AND C.VALT_BRNO = A.VALT_BRNO AND C.REMDR_RSK_GD_C = 'R') AS VALT21 ,(SELECT COUNT(VALT_BRNO) FROM SRBA_IMPRV_M D WHERE D.BAS_YYMM = A.BAS_YYMM AND D.VALT_BRNO = A.VALT_BRNO AND D.GYLJ_S_C = '3' AND IMPRV_CMPT_YN = 1) AS VALT22 FROM SRBA_V_REMDR_R A LEFT OUTER JOIN SRBA_IMPRV_M B ON A.BAS_YYMM = B.BAS_YYMM AND A.VALT_BRNO = B.VALT_BRNO WHERE 1=1 AND REMDR_RSK_GD_C = 'R' GROUP BY A.BAS_YYMM,A.VALT_BRNO ) DD ON AA.BRNO = DD.VALT_BRNO AND AA.BAS_YYMM = DD.BAS_YYMM ORDER BY AA.BRNO )T03 WHERE 1=1
AND T03.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND T03.BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
ORDER BY ROWNUM ASC

SELECT * FROM ( SELECT A.BAS_YYMM, -- 평가회차 A.LV1 , (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = A.LV1 AND GRP_C = 'S001' ) AS LV1_NM, -- 위험분류(Lv.1) '' AS LV2, '' AS LV2_NM, A.LV3, CASE WHEN A.LV3 = 'ALL' THEN '전체' ELSE (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = A.LV3 AND GRP_C = 'S003' ) END AS LV3_NM, -- 위험요소 C.MOFC_BRN_CCD, DECODE(C.MOFC_BRN_CCD, 'M', '본부부서', '영업점' ) AS MOFC_BRNO_NM, -- 부점 구분 A.BRNO, -- 소관부점 (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = A.BRNO) AS BRNO_NM, A.IMPRV_STRG_DT, -- 개선 요청 일자 A.IMPRV_STRG_CTNT, -- 개선 요청 사항 A.IMPRV_RSLT_DT, A.IMPRV_RSLT_CTNT, CASE WHEN A.IMPRV_S_C = 'N' THEN '미조치' WHEN A.IMPRV_S_C = 'S' THEN '조치중' ELSE '조치 완료' END AS IMPRV_S_C_NM, A.GYLJ_ID, A.GYLJ_DT, A.GYLJ_JKW_NO, A.GYLJ_S_C , -- 결재상태 (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R345' AND DTL_C = A.GYLJ_S_C) AS GYLJ_S_C_NM FROM SRBA_TJACT_IMPRV_I A JOIN NIC41B C ON A.BRNO = C.DPRT_CD WHERE 1=1 UNION ALL SELECT A.BAS_YYMM, -- 평가회차 A.LV1, (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.LV1 AND GRP_C = 'P001' ) AS LV1_NM, -- 통제분류(Lv.1) '' AS LV2, '' AS LV2_NM, A.LV3, CASE WHEN A.LV3 = 'ALL' THEN '전체' ELSE (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.LV3 AND GRP_C = 'P003' ) END AS LV3_NM, -- 위험요소 C.MOFC_BRN_CCD, DECODE(C.MOFC_BRN_CCD, 'M', '본부부서', '영업점' ) AS MOFC_BRNO_NM, -- 부점 구분 A.BRNO, -- 소관부점 (SELECT DEP_TITLE FROM C_DEP_INFO WHERE DEP_DESC = A.BRNO) AS BRNO_NM, A.IMPRV_STRG_DT, -- 개선 요청 일자 A.IMPRV_STRG_CTNT, -- 개선 요청 사항 A.IMPRV_RSLT_DT, A.IMPRV_RSLT_CTNT, CASE WHEN A.IMPRV_S_C = 'N' THEN '미조치' WHEN A.IMPRV_S_C = 'S' THEN '조치중' ELSE '조치 완료' END AS IMPRV_S_C_NM, A.GYLJ_ID, A.GYLJ_DT, A.GYLJ_JKW_NO, A.GYLJ_S_C , -- 결재상태 (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R345' AND DTL_C = A.GYLJ_S_C) AS GYLJ_S_C_NM FROM SRBA_TJACT_IMPRV_I A JOIN NIC41B C ON A.BRNO = C.DPRT_CD WHERE 1=1 AND (SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.LV1 AND GRP_C = 'P001' ) IS NOT NULL )T WHERE 1=1 AND T.LV1_NM IS NOT NULL
AND T.BAS_YYMM = #{BAS_YYMM,jdbcType=VARCHAR}
AND T.BRNO = #{BRNO,jdbcType=VARCHAR}
AND T.MOFC_BRN_CCD = #{MOFC_BRN_CCD,jdbcType=VARCHAR}
AND T.LV1 = #{LV1, jdbcType=VARCHAR}
AND T.LV3 = (SELECT DTL_C FROM SRBA_DTL_C WHERE GRP_C IN('P003','S003')AND DTL_C_NM LIKE '%' || #{LV3_NM} || '%')
AND T.IMPRV_S_C = #{IMPRV_S_C, jdbcType=VARCHAR}
AND T.GYLJ_S_C = #{GYLJ_S_C, jdbcType=VARCHAR}

