SELECT A.GYLJ_SER , A.GYLJ_JKW_NO , B.USER_NM AS HNDL_P_NM , C.BRNO , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = C.BRNO) AS BRN_NM , B.POSITION_CODE , (SELECT DISPLAY_NM FROM C_CD_NM WHERE LANG_CD = 'ko-KR' AND CD_ID = B.POSITION_CODE) AS POSITION_NAME , CASE WHEN A.GYLJ_S_C = '22' THEN 'Y' ELSE ' ' END AS SN_CCD_YN , A.NOTE_CTNT , TO_CHAR( TO_DATE(A.DR_DT,'YYYYMMDD') , 'YYYY-MM-DD' ) AS HNDL_DT , TO_CHAR( TO_DATE( (A.DR_DT || A.DR_TIME) ,'YYYYMMDDHH24MISS') , 'YYYY-MM-DD HH24:MI:SS' ) AS HNDL_DY_TM , A.DR_DT , A.DR_TIME , A.DR_OP_JKW_NO FROM C_GYLJ_H A , C_USER B , SRBA_TJACT_IMPRV_I C WHERE A.GYLJ_JKW_NO = B.LOGIN_ID AND A.GYLJ_ID = C.GYLJ_ID AND C.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND C.BRNO = #{BRNO, jdbcType=VARCHAR}
ORDER BY A.GYLJ_SER DESC

         SELECT  NVL(REAL_EDT,'N') AS REAL_EDT
