             AND T02.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
             AND T01.RBA_VALT_SMDV_C= #{RBA_VALT_SMDV_C, jdbcType=VARCHAR}

SELECT A.BAS_YYMM ,A.PROC_FLD_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R303' AND DTL_C= A.PROC_FLD_C ) AS PROC_FLD_NM ,A.PROC_LGDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R304' AND DTL_C= A.PROC_LGDV_C ) AS PROC_LGDV_NM ,A.PROC_MDDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R305' AND DTL_C= A.PROC_MDDV_C ) AS PROC_MDDV_NM ,A.PROC_SMDV_C ,A.PROC_SMDV_NM ,A.RSK_CAUS_CTNT ,A.USYN ,DECODE(A.USYN,'1','Y','0','N','') AS USYN_NM ,A.VALT_METH_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R307' AND DTL_C= A.VALT_METH_C ) AS VALT_METH_NM ,A.NOTE_CTNT ,A.DR_DT ,A.DR_TIME ,A.DR_OP_JKW_NO ,GET_LOGINID_NAME(A.DR_OP_JKW_NO) AS DR_OP_JKW_NM ,A.CHG_DT ,A.CHG_TIME ,A.CHG_OP_JKW_NO ,GET_LOGINID_NAME(A.CHG_OP_JKW_NO) AS CHG_OP_JKW_NM ,DECODE(A.PROC_FLD_C,'1',B.CNT,C.CNT) AS VALT_BRNO_CNT FROM SRBA_V_PROC_M A, (SELECT A.BAS_YYMM, PROC_SMDV_C, COUNT(*) AS CNT FROM SRBA_V_PROC_BRNO A, SRBA_VALT_BRNO B WHERE A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND A.BAS_YYMM = B.BAS_YYMM AND A.VALT_BRNO = B.BRNO AND TGT_YN='1' GROUP BY A.BAS_YYMM, PROC_SMDV_C ) B, (SELECT AA.BAS_YYMM, AA.PROC_SMDV_C, COUNT(*) AS CNT FROM SRBA_V_TONGJE_M AA ,SRBA_V_TJ_BRNO BB, SRBA_VALT_BRNO CC WHERE AA.PROC_SMDV_C = BB.PROC_SMDV_C(+) AND AA.TONGJE_NO = BB.TONGJE_NO(+) AND AA.BAS_YYMM = BB.BAS_YYMM(+) AND BB.BAS_YYMM = CC.BAS_YYMM AND BB.VALT_BRNO = CC.BRNO AND AA.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} GROUP BY AA.BAS_YYMM, AA.PROC_SMDV_C ) C WHERE 1=1 AND A.BAS_YYMM = B.BAS_YYMM(+) AND A.PROC_SMDV_C = B.PROC_SMDV_C(+) AND A.BAS_YYMM = C.BAS_YYMM(+) AND A.PROC_SMDV_C = C.PROC_SMDV_C(+) AND A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND A.PROC_FLD_C = #{PROC_FLD_C, jdbcType=VARCHAR}
AND A.PROC_LGDV_C = #{PROC_LGDV_C, jdbcType=VARCHAR}
AND A.PROC_MDDV_C = #{PROC_MDDV_C, jdbcType=VARCHAR}
AND A.PROC_SMDV_C = #{PROC_SMDV_C, jdbcType=VARCHAR}
AND A.VALT_METH_C = #{VALT_METH_C, jdbcType=VARCHAR}
AND A.USYN = #{USYN, jdbcType=VARCHAR}
ORDER BY PROC_FLD_C,PROC_LGDV_C,PROC_MDDV_C,PROC_SMDV_C

