SELECT DECODE(PROC_MDDV_C||DECODE(LENGTH(KEY),1,'0'||KEY,KEY),'',RPAD(#{GRP_C, jdbcType=VARCHAR},6,'0'),PROC_MDDV_C||DECODE(LENGTH(KEY),1,'0'||KEY,KEY)) AS RESULT_CD
	  FROM (
		SELECT MAX(PROC_MDDV_C) AS PROC_MDDV_C,SUBSTR(MAX(PROC_SMDV_C),LENGTH(MAX(PROC_SMDV_C))-1,LENGTH(MAX(PROC_SMDV_C)))+1 AS KEY
		  FROM SRBA_V_PROC_M
		 WHERE PROC_MDDV_C =  #{GRP_C , jdbcType=VARCHAR}

		   AND BAS_YYMM =#{BAS_YYMM,jdbcType=VARCHAR}

	  )

SELECT AAAA.*,(SELECT ROLE_NM FROM C_ROLE WHERE ROLE_ID = AAAA.GYLJ_STEP_ID) AS GYLJ_STEP FROM ( SELECT AAA.*, (SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C=AAA.GYLJ_G_C AND SNO='1') AS FIRST_ROLE_ID, CASE WHEN (GYLJ_S_C_NM = '저장' OR GYLJ_S_C_NM = '미수행') AND DPRT_CD ='J5' /*준법 부서 커스터마이징 필요*/ THEN (SELECT GYLJ_ROLE_ID||'' FROM C_GYLJ_D WHERE GYLJ_LINE_G_C='W01' AND SNO='1') WHEN (GYLJ_S_C_NM = '저장' OR GYLJ_S_C_NM = '미수행') AND DPRT_CD !='J5' /*준법 부서 커스터마이징 필요*/ THEN (SELECT GYLJ_ROLE_ID||'' FROM C_GYLJ_D WHERE GYLJ_LINE_G_C='W01' AND SNO='1') ELSE GYLJ_ROLE_ID||'' END AS GYLJ_STEP_ID FROM ( SELECT BB.DPRT_CD ,BB.DPRT_NM ,AA.AML_TJ_BRNO_YN ,BB.MOFC_BRN_CCD ,DECODE(BB.MOFC_BRN_CCD,'B','지점','본점') AS MOFC_BRN_YN ,DECODE(AA.AML_TJ_BRNO_YN,'1','Y','N') AS TJ_BRNO_YN ,NVL(CC.CNT,0) CNT ,NVL(EE.CNT,0) CNT_A ,NVL(FF.CNT,0) CNT_M ,AA.BAS_YYMM ,DD.GYLJ_ID /*,DECODE(AA.AML_TJ_BRNO_YN,'0','11',DD.GYLJ_S_C) AS GYLJ_S_C*/ /*,(SELECT DECODE(AA.AML_TJ_BRNO_YN,'0','완료',DTL_C_NM) AS NAME*/ ,DECODE(BB.MOFC_BRN_CCD,'B','11',DD.GYLJ_S_C) AS GYLJ_S_C ,(SELECT DECODE(BB.MOFC_BRN_CCD,'B','완료',DTL_C_NM) AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R325' AND DTL_C= DECODE(DD.GYLJ_S_C,NULL,0,DD.GYLJ_S_C) ) AS GYLJ_S_C_NM ,DD.GYLJ_JKW_NO ,(SELECT MAX(GYLJ_G_C) FROM SRBA_GYLJ_H WHERE GYLJ_ID=DD.GYLJ_ID) AS GYLJ_G_C ,GET_LOGINID_NAME(GYLJ_JKW_NO) AS GYLJ_JKW_NM ,DD.GYLJ_ROLE_ID ,(SELECT ROLE_NM FROM C_ROLE WHERE ROLE_ID = DD.GYLJ_ROLE_ID) AS ROLE_NM ,BB.HG_RNK_DPRT_CD FROM SRBA_VALT_BRNO AA , NIC41B BB, ( SELECT A.BAS_YYMM,B.VALT_BRNO,COUNT(*) AS CNT FROM SRBA_V_PROC_M A,SRBA_V_PROC_BRNO B WHERE A.BAS_YYMM=B.BAS_YYMM(+) AND A.PROC_FLD_C=B.PROC_FLD_C(+) AND A.PROC_LGDV_C=B.PROC_LGDV_C(+) AND A.PROC_MDDV_C=B.PROC_MDDV_C(+) AND A.PROC_SMDV_C=B.PROC_SMDV_C(+) AND A.USYN='1' AND A.PROC_FLD_C='1' AND B.TGT_YN ='1' AND B.BAS_YYMM = #{BAS_YYMM,jdbcType=VARCHAR} GROUP BY A.BAS_YYMM,B.VALT_BRNO ) CC , (SELECT D.BAS_YYMM,D.VALT_BRNO,D.GYLJ_S_C,GYLJ_ID,GYLJ_JKW_NO,GYLJ_ROLE_ID FROM ( SELECT BAS_YYMM,VALT_BRNO,GYLJ_S_C,GYLJ_ID,GYLJ_JKW_NO,GYLJ_ROLE_ID ,ROW_NUMBER() OVER (PARTITION BY VALT_BRNO ORDER BY GYLJ_ID DESC) RNUM FROM SRBA_V_PROC_GYLJ WHERE BAS_YYMM = #{BAS_YYMM,jdbcType=VARCHAR} ) D WHERE RNUM =1 ) DD, ( SELECT A.BAS_YYMM,B.VALT_BRNO,COUNT(*) AS CNT FROM SRBA_V_PROC_M A,SRBA_V_PROC_BRNO B WHERE A.BAS_YYMM=B.BAS_YYMM(+) AND A.PROC_FLD_C=B.PROC_FLD_C(+) AND A.PROC_LGDV_C=B.PROC_LGDV_C(+) AND A.PROC_MDDV_C=B.PROC_MDDV_C(+) AND A.PROC_SMDV_C=B.PROC_SMDV_C(+) AND A.USYN='1' AND A.PROC_FLD_C='1' AND B.TGT_YN ='1' AND A.VALT_METH_C ='1' /* 자동 */ AND B.BAS_YYMM = #{BAS_YYMM,jdbcType=VARCHAR} GROUP BY A.BAS_YYMM,B.VALT_BRNO ) EE , ( SELECT A.BAS_YYMM,B.VALT_BRNO,COUNT(*) AS CNT FROM SRBA_V_PROC_M A,SRBA_V_PROC_BRNO B WHERE A.BAS_YYMM=B.BAS_YYMM(+) AND A.PROC_FLD_C=B.PROC_FLD_C(+) AND A.PROC_LGDV_C=B.PROC_LGDV_C(+) AND A.PROC_MDDV_C=B.PROC_MDDV_C(+) AND A.PROC_SMDV_C=B.PROC_SMDV_C(+) AND A.USYN='1' AND A.PROC_FLD_C='1' AND A.VALT_METH_C ='2' /* 수기 */ AND B.TGT_YN ='1' AND B.BAS_YYMM = #{BAS_YYMM,jdbcType=VARCHAR} GROUP BY A.BAS_YYMM,B.VALT_BRNO ) FF WHERE USE_CCD='Y' AND AA.BRNO=BB.DPRT_CD AND AA.BRNO=CC.VALT_BRNO(+) AND AA.BRNO=DD.VALT_BRNO(+) AND AA.BRNO=EE.VALT_BRNO(+) AND AA.BRNO=FF.VALT_BRNO(+) AND AA.BAS_YYMM = #{BAS_YYMM,jdbcType=VARCHAR}
AND AA.BRNO = #{BRNO,jdbcType=VARCHAR}
AND AA.AML_TJ_BRNO_YN = #{AML_TJ_BRNO_YN,jdbcType=VARCHAR}
) AAA WHERE 1=1
AND AAA.MOFC_BRN_CCD = #{MOFC_BRN_CCD,jdbcType=VARCHAR}
)AAAA WHERE 1=1
AND AAAA.GYLJ_STEP_ID = #{GYLJ_STEP,jdbcType=VARCHAR}
ORDER BY DPRT_CD,HG_RNK_DPRT_CD,AML_TJ_BRNO_YN

SELECT A.BAS_YYMM ,A.PROC_FLD_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R303' AND DTL_C= A.PROC_FLD_C ) AS PROC_FLD_NM ,A.PROC_LGDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R304' AND DTL_C= A.PROC_LGDV_C ) AS PROC_LGDV_NM ,A.PROC_MDDV_C ,(SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R305' AND DTL_C= A.PROC_MDDV_C ) AS PROC_MDDV_NM ,A.PROC_SMDV_C ,A.PROC_SMDV_NM ,NVL(B.TGT_YN,'0') AS TGT_YN ,DECODE(B.TGT_YN,'1','Y','N') AS TGT_YN_NM ,NVL(B.VALT_BRNO,#{VALT_BRNO,jdbcType=VARCHAR}) AS VALT_BRNO FROM SRBA_V_PROC_M A, (SELECT TGT_YN ,BAS_YYMM,PROC_FLD_C,PROC_LGDV_C,PROC_MDDV_C,PROC_SMDV_C,VALT_BRNO FROM SRBA_V_PROC_BRNO WHERE VALT_BRNO = #{VALT_BRNO,jdbcType=VARCHAR} ) B WHERE A.BAS_YYMM=B.BAS_YYMM(+) AND A.PROC_FLD_C=B.PROC_FLD_C(+) AND A.PROC_LGDV_C=B.PROC_LGDV_C(+) AND A.PROC_MDDV_C=B.PROC_MDDV_C(+) AND A.PROC_SMDV_C=B.PROC_SMDV_C(+) AND A.USYN='1' AND A.PROC_FLD_C='1' AND A.BAS_YYMM= #{BAS_YYMM,jdbcType=VARCHAR}
AND A.PROC_FLD_C = #{PROC_FLD_C, jdbcType=VARCHAR}
AND A.PROC_LGDV_C = #{PROC_LGDV_C, jdbcType=VARCHAR}
AND A.PROC_MDDV_C = #{PROC_MDDV_C, jdbcType=VARCHAR}
AND B.TGT_YN = #{TGT_YN, jdbcType=VARCHAR}
ORDER BY PROC_FLD_C,PROC_LGDV_C

