SELECT * FROM ( SELECT M.BAS_YYMM , M.RSK_CATG1_C , ( SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = M.RSK_CATG1_C AND GRP_C = 'S001' ) AS RSK_CATG1_C_NM , M.RSK_CATG2_C , ( SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = M.RSK_CATG2_C AND GRP_C = 'S002' ) AS RSK_CATG2_C_NM , M.RSK_ELMT_C , ( SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = M.RSK_ELMT_C AND GRP_C = 'S003' ) AS RSK_ELMT_C_NM , CASE WHEN M.RSK_CATG1_C = 'R5' AND E.RA_ST_INTV_VAL IS NOT NULL THEN E.RA_ST_INTV_VAL || ' ~ ' || E.RA_ET_INTV_VAL ELSE ' ' END AS RA_INTV_VAL , E.RA_ST_INTV_VAL , E.RA_ITEM_CODE , M.RSK_ELMT_DTL_CTNT , M.RSK_CTNT , M.RSK_VALT_ITEM , ( SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = M.RSK_VALT_ITEM AND GRP_C = 'R342' ) AS RSK_VALT_ITEM_NM , M.RSK_VALT_CAL_STD --DECODE( RSK_VALT_CAL_STD , '1', '고객수', '거래금액' ) AS , DECODE( M.RSK_VALT_CAL_STD , '1', '고객수', '거래금액' ) AS RSK_VALT_CAL_STD_NM , M.EDD_YN , CASE WHEN E.RA_ST_INTV_VAL IS NULL THEN M.RSK_PNT ELSE E.RA_ITEM_SCR END AS RSK_PNT , M.INDV_YN , M.CORP_YN , M.I_MODEL_YN , M.B_MODEL_YN , M.USE_YN , M.RA_CHG_DT , M.COMMENT_CTNT , G.GYLJ_ID , G.GYLJ_S_C , CASE WHEN G.GYLJ_S_C IS NULL OR G.GYLJ_S_C = 0 THEN '미입력' ELSE (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R345' AND DTL_C = G.GYLJ_S_C ) END AS GYLJ_S_C_NM , CASE WHEN NVL(G.GYLJ_S_C, 0) = '3' THEN 'Y' /* 지표결재상태코드(A014) = 3(완료) */ ELSE 'N' END FINL_GYLJ_S /* 최종승인여부 */ , NVL(( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM C_GYLJ_H H WHERE H.GYLJ_ID = G.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM C_GYLJ_H WHERE GYLJ_ID = G.GYLJ_ID ) ), 0) AS GYLJ_ROLE_ID , ( select case when G.GYLJ_S_C = '22' then RTN_ROLE_ID else NEXT_GYLJ_ROLE_ID end as role_id from C_GYLJ_D where GYLJ_LINE_G_C = 'RBA01' and GYLJ_ROLE_ID = NVL( ( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM C_GYLJ_H H WHERE H.GYLJ_ID = G.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM C_GYLJ_H WHERE GYLJ_ID = G.GYLJ_ID ) ), 0) ) AS NEXT_GYLJ_ROLE_ID ,(SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' AND SNO = (SELECT MIN(SNO) FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' ) ) AS FIRST_GYLJ ,(SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' AND SNO = (SELECT MAX(SNO) FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' )) AS END_GYLJ FROM SRBA_RISK_ELMT_M M , SRBA_ETC_I E , SRBA_APPR_M G WHERE M.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND M.BAS_YYMM = E.BAS_YYMM(+) AND M.RSK_ELMT_C = E.RSK_ELMT_C(+) AND M.BAS_YYMM = G.BAS_YYMM(+) AND 'SRBA_RISK_ELMT_M' = G.TABLE_NM(+) AND M.RSK_CATG1_C != 'R3'
AND M.RSK_CATG1_C = #{RSK_CATG1_C, jdbcType=VARCHAR}
AND M.RSK_VALT_ITEM = #{RSK_VALT_ITEM, jdbcType=VARCHAR}
AND M.USE_YN = #{USE_YN, jdbcType=VARCHAR}
AND ( M.EDD_YN = #{EDD_YN, jdbcType=VARCHAR} OR ( #{EDD_YN, jdbcType=VARCHAR} = 'Z' AND EDD_YN != 'N' ) )
AND M.INDV_YN = #{INDV_YN, jdbcType=VARCHAR}
AND M.CORP_YN = #{CORP_YN, jdbcType=VARCHAR}
AND M.I_MODEL_YN = #{I_MODEL_YN, jdbcType=VARCHAR}
AND M.B_MODEL_YN = #{B_MODEL_YN, jdbcType=VARCHAR}
UNION ALL
SELECT M.BAS_YYMM , M.RSK_CATG1_C , ( SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = M.RSK_CATG1_C AND GRP_C = 'S001' ) AS RSK_CATG1_C_NM , M.RSK_CATG2_C , ( SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = M.RSK_CATG2_C AND GRP_C = 'S002' ) AS RSK_CATG2_C_NM , M.RSK_ELMT_C , ( SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = M.RSK_ELMT_C AND GRP_C = 'S003' ) AS RSK_ELMT_C_NM , ' ' AS RA_INTV_VAL , 0 AS RA_ST_INTV_VAL , ' ' AS RA_ITEM_CODE , M.RSK_ELMT_DTL_CTNT , M.RSK_CTNT , M.RSK_VALT_ITEM , ( SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = M.RSK_VALT_ITEM AND GRP_C = 'R342' ) AS RSK_VALT_ITEM_NM , M.RSK_VALT_CAL_STD --DECODE( RSK_VALT_CAL_STD , '1', '고객수', '거래금액' ) AS , DECODE( M.RSK_VALT_CAL_STD , '1', '고객수', '거래금액' ) AS RSK_VALT_CAL_STD_NM , M.EDD_YN , M.RSK_PNT AS RSK_PNT , M.INDV_YN , M.CORP_YN , M.I_MODEL_YN , M.B_MODEL_YN , M.USE_YN , M.RA_CHG_DT , M.COMMENT_CTNT , G.GYLJ_ID , G.GYLJ_S_C , CASE WHEN G.GYLJ_S_C IS NULL OR G.GYLJ_S_C = 0 THEN '미입력' ELSE (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R345' AND DTL_C = G.GYLJ_S_C ) END AS GYLJ_S_C_NM , CASE WHEN NVL(G.GYLJ_S_C, 0) = '3' THEN 'Y' /* 지표결재상태코드(A014) = 3(완료) */ ELSE 'N' END FINL_GYLJ_S /* 최종승인여부 */ , NVL(( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM C_GYLJ_H H WHERE H.GYLJ_ID = G.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM C_GYLJ_H WHERE GYLJ_ID = G.GYLJ_ID ) ), 0) AS GYLJ_ROLE_ID , ( select case when G.GYLJ_S_C = '22' then RTN_ROLE_ID else NEXT_GYLJ_ROLE_ID end as role_id from C_GYLJ_D where GYLJ_LINE_G_C = 'RBA01' and GYLJ_ROLE_ID = NVL( ( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM C_GYLJ_H H WHERE H.GYLJ_ID = G.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM C_GYLJ_H WHERE GYLJ_ID = G.GYLJ_ID ) ), 0) ) AS NEXT_GYLJ_ROLE_ID ,(SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' AND SNO = (SELECT MIN(SNO) FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' ) ) AS FIRST_GYLJ ,(SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' AND SNO = (SELECT MAX(SNO) FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' )) AS END_GYLJ FROM SRBA_RISK_ELMT_M M , SRBA_APPR_M G WHERE M.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND M.BAS_YYMM = G.BAS_YYMM(+) AND 'SRBA_RISK_ELMT_M' = G.TABLE_NM(+) AND M.RSK_CATG1_C = 'R3'
AND M.RSK_CATG1_C = #{RSK_CATG1_C, jdbcType=VARCHAR}
AND M.RSK_VALT_ITEM = #{RSK_VALT_ITEM, jdbcType=VARCHAR}
AND M.USE_YN = #{USE_YN, jdbcType=VARCHAR}
AND ( M.EDD_YN = #{EDD_YN, jdbcType=VARCHAR} OR ( #{EDD_YN, jdbcType=VARCHAR} = 'Z' AND EDD_YN != 'N' ) )
AND M.INDV_YN = #{INDV_YN, jdbcType=VARCHAR}
AND M.CORP_YN = #{CORP_YN, jdbcType=VARCHAR}
AND M.I_MODEL_YN = #{I_MODEL_YN, jdbcType=VARCHAR}
AND M.B_MODEL_YN = #{B_MODEL_YN, jdbcType=VARCHAR}
) ORDER BY RSK_ELMT_C, RA_ST_INTV_VAL

