) WHERE 1=1 AND DTL_C IS NULL
UNION ALL
SELECT RSK_CATG1_C_NM , RISK_ELMT_C AS RSK_ELMT_C , (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = RISK_VAL_ITEM AND GRP_C = 'R342' ) AS RSK_VALT_ITEM_NM , RISK_ELMT_NM AS RSK_ELMT_C_NM , RISK_HRSK_YN AS EDD_YN , '변경' AS MSG FROM ( SELECT (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = RISK_CATG1_C AND GRP_C = 'S001' ) AS RSK_CATG1_C_NM , B.RISK_ELMT_C , B.RISK_ELMT_NM , B.RISK_VAL_ITEM , B.RISK_HRSK_YN , A.EDD_YN FROM ( SELECT BAS_YYMM , RSK_ELMT_C , EDD_YN FROM SRBA_RISK_ELMT_M WHERE BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND RSK_CATG1_C != 'R3' ) A , RA_RISK_FACTOR_REQ B WHERE B.RISK_ELMT_C = A.RSK_ELMT_C(+)
) WHERE 1=1 AND EDD_YN IS NOT NULL AND EDD_YN != RISK_HRSK_YN

