		UPDATE SRBA_V_RSK_JIPYO_M A
		   SET GYLJ_ID = #{GYLJ_ID,jdbcType=VARCHAR}
			  ,GYLJ_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
			  ,GYLJ_S_C = #{GYLJ_S_C,jdbcType=VARCHAR}
			  ,GYLJ_JKW_NO = #{GYLJ_JKW_NO,jdbcType=VARCHAR}
              ,GYLJ_ROLE_ID  = CASE WHEN #{GYLJ_FLAG, jdbcType=VARCHAR} = '0' THEN (SELECT NEXT_GYLJ_ROLE_ID
                                                                              FROM C_GYLJ_D
                                                                             WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                                                               AND SNO           = 1)
                            WHEN #{GYLJ_FLAG, jdbcType=VARCHAR} = '1' THEN (SELECT RTN_ROLE_ID
                                                                              FROM C_GYLJ_D
                                                                             WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                                                               AND GYLJ_ROLE_ID  = A.GYLJ_ROLE_ID
                                                                               AND GYLJ_ROLE_ID  = #{ROLE_ID, jdbcType=NUMERIC})
                            ELSE (SELECT NEXT_GYLJ_ROLE_ID
                                    FROM C_GYLJ_D
                                   WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                     AND GYLJ_ROLE_ID  = A.GYLJ_ROLE_ID
                                     AND GYLJ_ROLE_ID  = #{ROLE_ID, jdbcType=NUMERIC})
                        END
		      ,CHG_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
		      ,CHG_TIME = TO_CHAR(SYSDATE,'HH24MISS')
		      ,CHG_OP_JKW_NO = #{CHG_OP_JKW_NO,jdbcType=VARCHAR}
		WHERE BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
		  AND RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR}
		  AND RSK_FAC  = #{RSK_FAC, jdbcType=VARCHAR}
		  AND RSK_INDCT= #{RSK_INDCT, jdbcType=VARCHAR}

