SELECT * FROM ( SELECT A.BAS_YYMM , A.CNTL_CATG1_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.CNTL_CATG1_C AND GRP_C = 'P001' ) AS CNTL_CATG1_C_NM , A.CNTL_CATG2_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.CNTL_CATG2_C AND GRP_C = 'P002' ) AS CNTL_CATG2_C_NM , A.CNTL_ELMN_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.CNTL_ELMN_C AND GRP_C = 'P003' ) AS CNTL_ELMN_C_NM , A.CNTL_ELMN_CTNT , A.CNTL_RSK_CTNT , A.EVAL_TYPE_CD , A.EVAL_MTHD_CTNT , CASE WHEN B.CNTL_ELMN_C IS NULL THEN '0' ELSE '1' END AS AUTO_EXT_YN , A.PROOF_DOC_LIST , A.USE_YN , A.CHG_RSN_CTNT , C.MERGED_BRNO_NM AS BRNO_NM , A.DR_DT , A.DR_TIME , A.DR_OP_JKW_NO , CC.FIX_YN , CC.FIX_YN_M , CC.ING_STEP , CC.ING_STEP_NM , G.GYLJ_ID , G.GYLJ_S_C , CASE WHEN G.GYLJ_S_C IS NULL OR G.GYLJ_S_C = 0 THEN '미입력' ELSE (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R345' AND DTL_C = G.GYLJ_S_C ) END AS GYLJ_S_C_NM , CASE WHEN NVL(G.GYLJ_S_C, 0) = '3' THEN 'Y' /* 지표결재상태코드(A014) = 3(완료) */ ELSE 'N' END FINL_GYLJ_S /* 최종승인여부 */ , NVL(( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM C_GYLJ_H H WHERE H.GYLJ_ID = G.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM C_GYLJ_H WHERE GYLJ_ID = G.GYLJ_ID ) ), 0) AS GYLJ_ROLE_ID , ( SELECT CASE WHEN G.GYLJ_S_C = '22' THEN RTN_ROLE_ID ELSE NEXT_GYLJ_ROLE_ID END AS ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' AND GYLJ_ROLE_ID = NVL( ( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM C_GYLJ_H H WHERE H.GYLJ_ID = G.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM C_GYLJ_H WHERE GYLJ_ID = G.GYLJ_ID ) ), 0) ) as NEXT_GYLJ_ROLE_ID ,(SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' AND SNO = (SELECT MIN(SNO) FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' ) ) AS FIRST_GYLJ ,(SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' AND SNO = (SELECT MAX(SNO) FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' )) AS END_GYLJ FROM SRBA_CNTL_ELMN_M A , SRBA_APPR_M G , ( SELECT DISTINCT BB.CNTL_ELMN_C FROM SRBA_CNTL_ELMN_M AA , SRBA_CNTL_ITEM_D BB WHERE AA.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND AA.BAS_YYMM = BB.BAS_YYMM AND AA.CNTL_CATG1_C = BB.CNTL_CATG1_C AND AA.CNTL_CATG2_C = BB.CNTL_CATG2_C AND AA.CNTL_ELMN_C = BB.CNTL_ELMN_C AND BB.AUTO_EXT_YN = '1' ) B , ( SELECT CNTL_ELMN_C , LISTAGG( BRNO_NM, ', ' ) WITHIN GROUP (ORDER BY BRNO ) AS MERGED_BRNO_NM FROM ( SELECT BB.CNTL_ELMN_C , BB.BRNO , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = BB.BRNO) BRNO_NM FROM SRBA_CNTL_ELMN_M AA , SRBA_CNTL_BRNO_I BB WHERE AA.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND AA.BAS_YYMM = BB.BAS_YYMM AND AA.CNTL_ELMN_C = BB.CNTL_ELMN_C AND BB.TGT_YN = '1' ) GROUP BY CNTL_ELMN_C ) C , ( SELECT T01.BAS_YYMM , T01.FIX_YN , T02.FIX_YN AS FIX_YN_M , T02.ING_STEP , NVL((SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R343' AND DTL_C = T02.ING_STEP ),'일정정보입력') AS ING_STEP_NM FROM SRBA_VALT_SCHD_D T01 , SRBA_VALT_SCHD_M T02 WHERE T01.BAS_YYMM = T02.BAS_YYMM AND T01.RBA_VALT_SMDV_C = '3.2' AND T01.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} ) CC WHERE A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND A.CNTL_ELMN_C = B.CNTL_ELMN_C(+) AND A.CNTL_ELMN_C = C.CNTL_ELMN_C(+) AND A.BAS_YYMM = CC.BAS_YYMM(+) AND A.BAS_YYMM = G.BAS_YYMM(+) AND 'SRBA_CNTL_ELMN_M' = G.TABLE_NM(+)
AND A.CNTL_CATG1_C = #{CNTL_CATG1_C, jdbcType=VARCHAR}
AND A.CNTL_CATG2_C = #{CNTL_CATG2_C, jdbcType=VARCHAR}
AND A.EVAL_TYPE_CD = #{EVAL_TYPE_CD, jdbcType=VARCHAR}
AND A.USE_YN = #{USE_YN, jdbcType=VARCHAR}
)
WHERE 1=1
AND CNTL_ELMN_C_NM like '%' || #{CNTL_ELMN_C_NM, jdbcType=VARCHAR} || '%'
AND BRNO_NM like '%' || #{BRNO_NM, jdbcType=VARCHAR} || '%'
AND AUTO_EXT_YN = #{AUTO_EXT_YN, jdbcType=VARCHAR}
ORDER BY CNTL_ELMN_C

SELECT A.BAS_YYMM, A.PROC_LGDV_C AS TONGJE_LGDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R312' AND DTL_C= A.PROC_LGDV_C ) AS TONGJE_LGDV_NM , A.PROC_MDDV_C AS TONGJE_MDDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R313' AND DTL_C= A.PROC_MDDV_C ) AS TONGJE_MDDV_NM , A.PROC_SMDV_C AS TONGJE_SMDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R314' AND DTL_C= A.PROC_SMDV_C ) AS TONGJE_SMDV_NM , A.TONGJE_NO, A.TONGJE_ACT_TITE, A.TONGJE_ISP_STEP, A.DSGN_VALT_PROF, A.DSGN_VALT_TP_C, A.VALD_VALT_METH_C, A.VALT_METH_C, A.OPR_VALT_JIPYO_NM, A.TONGJE_SCOR_OFFR_C, A.DR_DT, A.DR_TIME, A.DR_OP_JKW_NO, A.CHG_DT, A.CHG_TIME, A.CHG_OP_JKW_NO FROM SRBA_V_TONGJE_M A WHERE BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND A.PROC_LGDV_C = #{TONGJE_LGDV_C, jdbcType=VARCHAR}
AND A.PROC_MDDV_C = #{TONGJE_MDDV_C, jdbcType=VARCHAR}
AND A.PROC_SMDV_C = #{TONGJE_SMDV_C, jdbcType=VARCHAR}
ORDER BY PROC_LGDV_C,PROC_MDDV_C,PROC_SMDV_C

		SELECT NVL(TONGJE_MDDV_C||DECODE(LENGTH(KEY),1,'0'||KEY,KEY),FIRST_REGI) AS RESULT_CD
