SELECT AA.*, BB.TONGJE_ALLT FROM ( SELECT DISTINCT A.BAS_YYMM, A.TONGJE_FLD_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R312' AND DTL_C= A.TONGJE_FLD_C ) AS TONGJE_FLD_NM , A.TONGJE_LGDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R313' AND DTL_C= A.TONGJE_LGDV_C ) AS TONGJE_LGDV_NM , A.TONGJE_MDDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R314' AND DTL_C= A.TONGJE_MDDV_C ) AS TONGJE_MDDV_NM FROM SRBA_V_TONGJE_M A ) AA , SRBA_TJ_ALLT_I BB WHERE AA.BAS_YYMM=BB.BAS_YYMM(+) AND AA.TONGJE_FLD_C=BB.TONGJE_FLD_C(+) AND AA.TONGJE_LGDV_C=BB.TONGJE_LGDV_C(+) AND AA.TONGJE_MDDV_C=BB.TONGJE_MDDV_C(+) AND AA.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND AA.TONGJE_FLD_C = #{TONGJE_FLD_C, jdbcType=VARCHAR}
AND AA.TONGJE_LGDV_C = #{TONGJE_LGDV_C, jdbcType=VARCHAR}
AND AA.TONGJE_MDDV_C = #{TONGJE_MDDV_C, jdbcType=VARCHAR}
ORDER BY AA.TONGJE_FLD_C, AA.TONGJE_LGDV_C ,AA.TONGJE_MDDV_C

		SELECT NVL(SUM(TONGJE_ALLT),0) AS TONGJE_ALLT_SUM
  		 FROM (
	  		SELECT  DISTINCT A.TONGJE_FLD_C,A.TONGJE_LGDV_C,A.TONGJE_MDDV_C,B.TONGJE_ALLT
	          FROM SRBA_V_TONGJE_M A , SRBA_TJ_ALLT_I B
	         WHERE A.BAS_YYMM=B.BAS_YYMM
	           AND A.TONGJE_FLD_C=B.TONGJE_FLD_C
	           AND A.TONGJE_LGDV_C=B.TONGJE_LGDV_C
	           AND A.TONGJE_MDDV_C=B.TONGJE_MDDV_C
	           AND A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}

		 	   AND A.TONGJE_FLD_C = #{TONGJE_FLD_C, jdbcType=VARCHAR}


			   AND A.TONGJE_LGDV_C = #{TONGJE_LGDV_C, jdbcType=VARCHAR}


		 	   AND A.TONGJE_MDDV_C = #{TONGJE_MDDV_C, jdbcType=VARCHAR}

     )

SELECT A.BAS_YYMM , A.BRNO , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.BRNO) BRNO_NM , A.HGRK_BRNO , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.HGRK_BRNO) HGRK_BRNO_NM , A.AML_TJ_BRNO_YN , A.DR_DT , A.DR_TIME , A.DR_OP_JKW_NO , B.MOFC_BRN_CCD , GET_CODE_NAME('M043',B.MOFC_BRN_CCD) AS MOFC_BRN_NAME , (SELECT COUNT(1) AS CNT from SRBA_CNTL_BRNO_I WHERE BAS_YYMM = A.BAS_YYMM AND BRNO = A.BRNO AND TGT_YN = '1') AS COUNT , JI.LOGIN_ID RUSER_ID, JI.USER_NM RNM, JI.EMAIL AS RXEMAIL, JI.EMAIL AS REMAIL, BON.LOGIN_ID BUSER_ID, BON.USER_NM BNM, BON.EMAIL AS BXEMAIL, BON.EMAIL AS BEMAIL , CASE WHEN G.GYLJ_S_C IS NULL OR G.GYLJ_S_C = 0 THEN '미입력' ELSE (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R345' AND DTL_C = G.GYLJ_S_C ) END AS GYLJ_S_C_NM FROM SRBA_VALT_BRNO A , NIC41B B , ( SELECT D.DEP_ID, LISTAGG(U.LOGIN_ID,',') WITHIN GROUP( ORDER BY U.LOGIN_ID) LOGIN_ID, DEP_DESC, DEP_TP_CD, DEP_TITLE, LISTAGG(U.USER_NM,',') WITHIN GROUP( ORDER BY U.USER_NM) USER_NM, ROLE_ID, MAX(U.EMAIL) EMAIL FROM C_DEP_INFO D, C_USER U, C_USER_GROUP_ROLE R WHERE 1 =1 AND D.DEP_ID = U.DEP_ID AND U.USER_ID = R.USER_ID AND R.ROLE_ID = '105' GROUP BY D.DEP_ID, DEP_DESC, DEP_TP_CD, DEP_TITLE, ROLE_ID ) JI, (SELECT D.DEP_ID, LISTAGG(U.LOGIN_ID,',') WITHIN GROUP( ORDER BY U.LOGIN_ID) LOGIN_ID, DEP_DESC, DEP_TP_CD, DEP_TITLE, LISTAGG(U.USER_NM,',') WITHIN GROUP(ORDER BY U.USER_NM) USER_NM, ROLE_ID, MAX(U.EMAIL) EMAIL FROM C_DEP_INFO D, C_USER U, C_USER_GROUP_ROLE R WHERE 1 = 1 AND D.DEP_ID = U.DEP_ID AND U.USER_ID = R.USER_ID AND R.ROLE_ID = '6' GROUP BY D.DEP_ID, DEP_DESC, DEP_TP_CD, DEP_TITLE, ROLE_ID ) BON , SRBA_APPR_M G WHERE 1=1 AND A.BAS_YYMM =#{BAS_YYMM,jdbcType=VARCHAR} AND A.BRNO = B.DPRT_CD AND A.BRNO = JI.DEP_DESC(+) AND A.BRNO = BON.DEP_DESC(+) AND A.BAS_YYMM = G.BAS_YYMM(+) AND 'SRBA_CNTL_ELMN_M' = G.TABLE_NM(+)
AND A.BRNO = #{BRNO , jdbcType=VARCHAR}
ORDER BY A.BRNO , A.HGRK_BRNO

SELECT * FROM ( SELECT A.BAS_YYMM , NVL(B.BRNO,' ' ) AS BRNO , A.CNTL_CATG1_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.CNTL_CATG1_C AND GRP_C = 'P001' ) AS CNTL_CATG1_C_NM , A.CNTL_CATG2_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.CNTL_CATG2_C AND GRP_C = 'P002' ) AS CNTL_CATG2_C_NM , A.CNTL_ELMN_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.CNTL_ELMN_C AND GRP_C = 'P003' ) AS CNTL_ELMN_C_NM , A.CNTL_ELMN_CTNT , A.CNTL_RSK_CTNT , A.EVAL_TYPE_CD , A.EVAL_MTHD_CTNT , A.PROOF_DOC_LIST , NVL(B.TGT_YN,'0') AS TGT_YN , NVL(A.USE_YN,'0') AS USE_YN , A.CHG_RSN_CTNT , B.DR_DT , B.DR_TIME , B.DR_OP_JKW_NO , CC.FIX_YN , CC.FIX_YN_M , CC.ING_STEP , CC.ING_STEP_NM , CC.VALT_SDT , CC.VALT_EDT , CC.TGT_TRN_SDT , CC.TGT_TRN_EDT FROM SRBA_CNTL_ELMN_M A , SRBA_CNTL_BRNO_I B , ( SELECT T01.BAS_YYMM , T01.FIX_YN , T02.FIX_YN AS FIX_YN_M , T02.ING_STEP , NVL((SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R343' AND DTL_C = T02.ING_STEP ),'일정정보입력') AS ING_STEP_NM , T01.VALT_SDT , T01.VALT_EDT , T01.TGT_TRN_SDT , T01.TGT_TRN_EDT FROM SRBA_VALT_SCHD_D T01 , SRBA_VALT_SCHD_M T02 WHERE T01.BAS_YYMM = T02.BAS_YYMM AND T01.RBA_VALT_SMDV_C = '3.3' AND T01.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} ) CC WHERE A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND A.BAS_YYMM = B.BAS_YYMM(+) AND A.CNTL_ELMN_C = B.CNTL_ELMN_C(+) AND A.BAS_YYMM = CC.BAS_YYMM(+)
AND B.BRNO(+) = #{BRNO , jdbcType=VARCHAR}
AND A.CNTL_CATG1_C = #{CNTL_CATG1_C, jdbcType=VARCHAR}
AND A.CNTL_CATG2_C = #{CNTL_CATG2_C, jdbcType=VARCHAR}
AND A.USE_YN = #{USE_YN , jdbcType=VARCHAR}
) WHERE 1=1
AND CNTL_ELMN_C_NM like '%' || #{CNTL_ELMN_C_NM, jdbcType=VARCHAR} || '%'
ORDER BY CNTL_ELMN_C

