SELECT * FROM ( SELECT A.BAS_YYMM , A.BRNO , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.BRNO) BRNO_NM , B.HG_RNK_DPRT_CD AS HGRK_BRNO , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = B.HG_RNK_DPRT_CD) HGRK_BRNO_NM , A.CNTL_CATG1_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.CNTL_CATG1_C AND GRP_C = 'P001' ) AS CNTL_CATG1_C_NM , A.CNTL_CATG2_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.CNTL_CATG2_C AND GRP_C = 'P002' ) AS CNTL_CATG2_C_NM , A.CNTL_ELMN_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = A.CNTL_ELMN_C AND GRP_C = 'P003' ) AS CNTL_ELMN_C_NM , A.EVAL_TYPE_CD , CASE WHEN A.EVAL_TYPE_CD = '1' THEN '단일 Y/N' WHEN A.EVAL_TYPE_CD = '2' THEN '복수 Y/N' WHEN A.EVAL_TYPE_CD = '3' THEN '실적입력' ELSE ' ' END AS EVAL_TYPE_CD_NM , CASE WHEN TRIM(A.ATTCH_FILE_NO) IS NULL THEN 'N' ELSE 'Y' END AS FILE_YN , CASE WHEN G.GYLJ_S_C IS NULL AND A.CNT_PNT = 0 THEN '미작성' WHEN G.GYLJ_S_C IS NULL AND A.CNT_PNT > 0 THEN '작성중' WHEN G.GYLJ_S_C = '22' THEN '작성중' ELSE '작성완료' END AS WRITEN_YN , A.CNT_PNT || '%' AS CNT_PNT , A.CNTNT , A.CHG_RSN_CTNT , A.DR_DT , A.DR_TIME , A.DR_OP_JKW_NO , C.CNTL_ELMN_CTNT , C.CNTL_RSK_CTNT , C.EVAL_MTHD_CTNT , C.PROOF_DOC_LIST , CC.FIX_YN , CC.FIX_YN_M , CC.ING_STEP , CC.ING_STEP_NM , G.GYLJ_ID , CASE WHEN G.GYLJ_S_C IS NULL AND A.CNT_PNT = 0 THEN '0' WHEN G.GYLJ_S_C IS NULL AND A.CNT_PNT > 0 THEN '5' ELSE G.GYLJ_S_C END AS GYLJ_S_C , CASE WHEN A.BRNO = '20500' AND G.GYLJ_S_C IS NULL AND A.CNT_PNT >= 0 THEN '본점담당자' WHEN A.BRNO = '20500' AND G.GYLJ_S_C IN ( '0','5','22' ) THEN '본점담당자' WHEN G.GYLJ_S_C IS NULL AND A.CNT_PNT >= 0 THEN 'RBA 담당자' WHEN G.GYLJ_S_C IN ( '0','5','22' ) THEN 'RBA 담당자' WHEN G.GYLJ_S_C IN ( '12' ) THEN '보고책임자' WHEN G.GYLJ_S_C IN ( '13' ) THEN 'RBA/AML 책임자' WHEN G.GYLJ_S_C = '23' THEN '본점담당자' WHEN G.GYLJ_S_C = '32' THEN '보고책임자' WHEN G.GYLJ_S_C = '3' THEN ' ' ELSE '업무' END AS ROLEID , CASE WHEN G.GYLJ_S_C IS NULL AND A.CNT_PNT = 0 THEN '' WHEN G.GYLJ_S_C IS NULL AND A.CNT_PNT > 0 THEN '미상신' ELSE (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R346' AND DTL_C = G.GYLJ_S_C ) END AS GYLJ_S_C_NM , CASE WHEN NVL(G.GYLJ_S_C, 0) = '3' THEN 'Y' /* 지표결재상태코드(A014) = 3(완료) */ ELSE 'N' END FINL_GYLJ_S /* 최종승인여부 */ , NVL(( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM C_GYLJ_H H WHERE H.GYLJ_ID = G.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM C_GYLJ_H WHERE GYLJ_ID = G.GYLJ_ID ) ), 0) AS GYLJ_ROLE_ID , ( SELECT CASE WHEN G.GYLJ_S_C = '22' THEN RTN_ROLE_ID ELSE NEXT_GYLJ_ROLE_ID END AS ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' AND GYLJ_ROLE_ID = NVL( ( SELECT NVL(H.ROLE_ID, 0) AS ROLE_ID FROM C_GYLJ_H H WHERE H.GYLJ_ID = G.GYLJ_ID AND H.GYLJ_SER = ( SELECT MAX(GYLJ_SER) FROM C_GYLJ_H WHERE GYLJ_ID = G.GYLJ_ID ) ), 0) ) as NEXT_GYLJ_ROLE_ID ,(SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' AND SNO = (SELECT MIN(SNO) FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' ) ) AS FIRST_GYLJ ,(SELECT GYLJ_ROLE_ID FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' AND SNO = (SELECT MAX(SNO) FROM C_GYLJ_D WHERE GYLJ_LINE_G_C = 'RBA01' )) AS END_GYLJ FROM SRBA_V_CNTL_ELMN_M A , NIC41B B , SRBA_CNTL_ELMN_M C , SRBA_APPR_M G , ( SELECT T01.BAS_YYMM , T01.FIX_YN , T02.FIX_YN AS FIX_YN_M , T02.ING_STEP , NVL((SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R343' AND DTL_C = T02.ING_STEP ),'일정정보입력') AS ING_STEP_NM FROM SRBA_VALT_SCHD_D T01 , SRBA_VALT_SCHD_M T02 WHERE T01.BAS_YYMM = T02.BAS_YYMM AND T01.RBA_VALT_SMDV_C = '3.4' AND T01.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} ) CC WHERE A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND A.BRNO = B.DPRT_CD(+) AND A.BAS_YYMM = C.BAS_YYMM AND A.CNTL_CATG1_C = C.CNTL_CATG1_C AND A.CNTL_CATG2_C = C.CNTL_CATG2_C AND A.CNTL_ELMN_C = C.CNTL_ELMN_C AND A.BAS_YYMM = G.BAS_YYMM(+) AND A.CNTL_ELMN_C = G.LV3(+) AND A.BRNO = G.BRNO(+) AND 'SRBA_V_CNTL_ELMN_M' = G.TABLE_NM(+) AND A.BAS_YYMM = CC.BAS_YYMM(+) AND ( A.BRNO, A.CNTL_ELMN_C ) IN ( SELECT BRNO, CNTL_ELMN_C FROM SRBA_CNTL_BRNO_ITEM WHERE BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} GROUP BY CNTL_ELMN_C , BRNO )
AND A.BRNO = #{BRNO, jdbcType=VARCHAR}
AND A.CNTL_CATG1_C = #{CNTL_CATG1_C, jdbcType=VARCHAR}
AND A.CNTL_CATG2_C = #{CNTL_CATG2_C, jdbcType=VARCHAR}
AND A.EVAL_TYPE_CD = #{EVAL_TYPE_CD, jdbcType=VARCHAR}
AND A.WRITEN_YN = #{WRITEN_YN, jdbcType=VARCHAR}
) WHERE 1=1
AND CNTL_ELMN_C_NM like '%' || #{CNTL_ELMN_C, jdbcType=VARCHAR} || '%'
AND GYLJ_S_C = #{GYLJ_S_C, jdbcType=VARCHAR}
ORDER BY BRNO, CNTL_ELMN_C

SELECT * FROM (SELECT BAS_YYMM, PROC_LGDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R304' AND DTL_C= A.PROC_LGDV_C ) AS PROC_LGDV_NM , A.PROC_MDDV_C AS PROC_MDDV_C, (SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R305' AND DTL_C= A.PROC_MDDV_C ) AS PROC_MDDV_NM , A.PROC_SMDV_C, (SELECT MAX(PROC_SMDV_NM) FROM SRBA_V_PROC_M WHERE PROC_SMDV_C = A.PROC_SMDV_C AND BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} ) AS PROC_SMDV_NM, NVL((SELECT DECODE(PROC_SMDV_C,'','N','Y') FROM SRBA_V_PROC_TJ_MP WHERE 1=1
AND TONGJE_SMDV_C = #{TONGJE_SMDV_C, jdbcType=VARCHAR}
AND PROC_SMDV_C = A.PROC_SMDV_C AND BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} ),'N') AS KBN FROM SRBA_V_PROC_M A WHERE A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} AND A.PROC_FLD_C ='1' ORDER BY KBN DESC, PROC_SMDV_C )
WHERE KBN = #{USE_YN, jdbcType=VARCHAR}

