INSERT INTO SRBA_CNTL_BRNO_ITEM (
			 BAS_YYMM
			,CNTL_CATG1_C
			,CNTL_CATG2_C
			,CNTL_ELMN_C
			,BRNO
			,CNTL_ITEM_C
			,CNTL_ITEM_DE_C
			,SNO
			,CHECK_YN
			,CNTL_VALUE
			,DR_DT
			,DR_TIME
			,DR_OP_JKW_NO
			)
	VALUES(
			 #{BAS_YYMM,jdbcType=VARCHAR}
			,#{CNTL_CATG1_C,jdbcType=VARCHAR}
			,#{CNTL_CATG2_C,jdbcType=VARCHAR}
			,#{CNTL_ELMN_C,jdbcType=VARCHAR}
			,#{BRNO,jdbcType=VARCHAR}
			,#{CNTL_ITEM_C,jdbcType=VARCHAR}
			,#{CNTL_ITEM_DE_C,jdbcType=VARCHAR}
			,#{SNO,jdbcType=VARCHAR}
			,#{CHECK_YN,jdbcType=VARCHAR}
			,#{CNTL_VALUE,jdbcType=VARCHAR}
			,TO_CHAR(SYSDATE,'YYYYMMDD')
			,TO_CHAR(SYSDATE,'HH24MISS')
			,#{DR_OP_JKW_NO,jdbcType=VARCHAR}
		)

UPDATE SRBA_CNTL_BRNO_ITEM
	SET CNTL_VALUE = #{CNTL_VALUE, jdbcType=VARCHAR}
	 ,  CHECK_YN = #{CHECK_YN, jdbcType=VARCHAR}
	 ,  DR_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
	 ,  DR_TIME = TO_CHAR(SYSDATE,'HH24MISS')
	 ,  DR_OP_JKW_NO = #{DR_OP_JKW_NO,jdbcType=VARCHAR}
WHERE BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND   CNTL_ELMN_C = #{CNTL_ELMN_C, jdbcType=VARCHAR}
AND   BRNO = #{BRNO, jdbcType=VARCHAR}
AND   CNTL_ITEM_DE_C = #{CNTL_ITEM_DE_C, jdbcType=VARCHAR}

 		UPDATE SRBA_V_CNTL_ELMN_M
 		 SET CNTNT = #{CNTNT, jdbcType=VARCHAR}
 		 ,   WRITEN_YN = '1'
 		 ,   CNT_PNT = #{CNT_PNT, jdbcType=VARCHAR}
 		 WHERE BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
		 AND   CNTL_ELMN_C = #{CNTL_ELMN_C, jdbcType=VARCHAR}
		 AND   BRNO = #{BRNO, jdbcType=VARCHAR}

