UPDATE SRBA_CNTL_BRNO_ITEM
	SET CNTL_VALUE = #{CNTL_VALUE, jdbcType=VARCHAR}
	 ,  CHECK_YN = #{CHECK_YN, jdbcType=VARCHAR}
	 ,  DR_DT = TO_CHAR(SYSDATE,'YYYYMMDD')
	 ,  DR_TIME = TO_CHAR(SYSDATE,'HH24MISS')
	 ,  DR_OP_JKW_NO = #{DR_OP_JKW_NO,jdbcType=VARCHAR}
