AND   CNTL_ELMN_C = #{CNTL_ELMN_C, jdbcType=VARCHAR}
AND   BRNO = #{BRNO, jdbcType=VARCHAR}
AND   SNO = #{SNO, jdbcType=VARCHAR}

mapper.select:
SELECT 0 AS SORT_ORDER ,'S0000' AS HG_RNK_DPRT_CD -- 부점구분코드 ,'전체' AS MOFC_BRNO_NM -- 부점구분명 , '99999' AS BRNO , '삼성증권' AS BRNO_NM -- 평가대상부점 , 'P00' AS CNTL_CATG1_C , '통제요소 전체' AS CNTL_CATG1_C_NM -- 위험분류 , TONGJE_VAL -- 통제효과성점수 , BF_TONGJE_VAL -- 직전 통제효과성점수 , CASE WHEN NVL(TONGJE_VAL,0) = NVL(BF_TONGJE_VAL,0) THEN '유지' WHEN NVL(TONGJE_VAL,0) > NVL(BF_TONGJE_VAL,0) THEN '상승' ELSE '하락' END AS UP_DOWN_INFO , CASE WHEN NVL(TONGJE_VAL,0) = NVL(BF_TONGJE_VAL,0) THEN '0' WHEN NVL(TONGJE_VAL,0) > NVL(BF_TONGJE_VAL,0) THEN 'R' ELSE 'B' END AS UP_DOWN_COLOR FROM (
SELECT 'S0000' AS HG_RNK_DPRT_CD -- 부점구분코드 ,'전체' AS MOFC_BRNO_NM -- 부점구분명 , '99999' AS BRNO , '삼성증권' AS BRNO_NM -- 평가대상부점 , 'P00' AS CNTL_CATG1_C , ROUND(AVG(A.TONGJE_VAL),2) AS TONGJE_VAL -- 통제 효과성 점수 , ROUND(AVG(A.BF_TONGJE_VAL),2) AS BF_TONGJE_VAL -- 직전 통제 효과성 점수 FROM SRBA_V_CNTL_ELMN_SCORE A INNER JOIN NIC41B B ON A.BRNO = B.DPRT_CD WHERE A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} -- GROUP BY B.HG_RNK_DPRT_CD, A.BRNO , A.CNTL_CATG1_C
) WHERE 1=1
AND BRNO = #{BRNO, jdbcType=VARCHAR}
GROUP BY HG_RNK_DPRT_CD, BRNO , CNTL_CATG1_C , TONGJE_VAL ,BF_TONGJE_VAL
UNION ALL
SELECT 1 AS SORT_ORDER , HG_RNK_DPRT_CD , MOFC_BRNO_NM , BRNO , BRNO_NM , CNTL_CATG1_C , ( SELECT DTL_C_NM FROM KRBA_DTL_C WHERE DTL_C = CNTL_CATG1_C AND GRP_C = 'P001' ) AS CNTL_CATG1_C_NM -- 위험분류 , TONGJE_VAL -- 통제효과성점수 , BF_TONGJE_VAL -- 직전 통제효과성점수 , CASE WHEN NVL(TONGJE_VAL,0) = NVL(BF_TONGJE_VAL,0) THEN '유지' WHEN NVL(TONGJE_VAL,0) > NVL(BF_TONGJE_VAL,0) THEN '상승' ELSE '하락' END AS UP_DOWN_INFO , CASE WHEN NVL(TONGJE_VAL,0) = NVL(BF_TONGJE_VAL,0) THEN '0' WHEN NVL(TONGJE_VAL,0) > NVL(BF_TONGJE_VAL,0) THEN 'R' ELSE 'B' END AS UP_DOWN_COLOR FROM ( SELECT B.HG_RNK_DPRT_CD , CASE WHEN B.HG_RNK_DPRT_CD IS NULL THEN '전체' ELSE DECODE(B.MOFC_BRN_CCD, 'M', '본부부서', '영업점' ) END AS MOFC_BRNO_NM , A.BRNO , (SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.BRNO) AS BRNO_NM -- 평가대상부점 , A.CNTL_CATG1_C , ROUND(AVG(A.TONGJE_VAL),2) AS TONGJE_VAL -- 통제 효과성 점수 , ROUND(AVG(A.BF_TONGJE_VAL),2) AS BF_TONGJE_VAL -- 직전 통제 효과성 점수 FROM SRBA_V_CNTL_ELMN_SCORE A INNER JOIN NIC41B B ON A.BRNO = B.DPRT_CD WHERE A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} GROUP BY B.HG_RNK_DPRT_CD, B.MOFC_BRN_CCD, A.BRNO , A.CNTL_CATG1_C ) WHERE 1=1
AND CNTL_CATG1_C = #{CNTL_CATG1_C, jdbcType=VARCHAR}
AND TONGJE_VAL > BF_TONGJE_VAL
AND TONGJE_VAL < BF_TONGJE_VAL
AND TONGJE_VAL = BF_TONGJE_VAL
AND BRNO = #{BRNO, jdbcType=VARCHAR}
ORDER BY SORT_ORDER ,BRNO, CNTL_CATG1_C ASC

	 	SELECT AA.RULE_NO,(SELECT RULE_NM FROM SRBA_KRI_RULE_M WHERE RULE_NO=AA.RULE_NO)  AS RULE_NM,
	           AA.BAS_YYMM AS BAS_YYMM_1,AA.RULE_V_PNT AS RULE_V_PNT_1, AA.RULE_FREQ AS RULE_FREQ_1 ,
       		   BB.BAS_YYMM AS BAS_YYMM_2,BB.RULE_V_PNT AS RULE_V_PNT_2, BB.RULE_FREQ AS RULE_FREQ_2 ,
       		   CC.BAS_YYMM AS BAS_YYMM_3,CC.RULE_V_PNT AS RULE_V_PNT_3, CC.RULE_FREQ AS RULE_FREQ_3
		  FROM (
		      SELECT A.BAS_YYMM, A.RULE_NO, A.RULE_V, A.RULE_V_PNT, A.RULE_FREQ, A.RULE_VALT_GD_C, A.DR_DT, A.DR_TIME, A.DR_OP_JKW_NO
		        FROM SRBA_KRI_R_EXTR_M A
		       WHERE BAS_YYMM=#{BAS_YYMM_1, jdbcType=VARCHAR}
		       ) AA ,
		      (SELECT B.BAS_YYMM, B.RULE_NO, B.RULE_V, B.RULE_V_PNT, B.RULE_FREQ, B.RULE_VALT_GD_C, B.DR_DT, B.DR_TIME, B.DR_OP_JKW_NO
		        FROM SRBA_KRI_R_EXTR_M B
		       WHERE BAS_YYMM=#{BAS_YYMM_2, jdbcType=VARCHAR}
		       ) BB,
		      (SELECT C.BAS_YYMM, C.RULE_NO, C.RULE_V, C.RULE_V_PNT, C.RULE_FREQ, C.RULE_VALT_GD_C, C.DR_DT, C.DR_TIME, C.DR_OP_JKW_NO
		        FROM SRBA_KRI_R_EXTR_M C
		       WHERE BAS_YYMM= #{BAS_YYMM_3, jdbcType=VARCHAR}
		       ) CC
		WHERE AA.RULE_NO = BB.RULE_NO(+)
		  AND AA.RULE_NO = CC.RULE_NO(+)
		ORDER BY RULE_NO

SELECT A.BAS_YYMM,A.KRI_NO,A.KRI_V,A.KRI_AVG_PNT,A.KRI_FREQ,DECODE(A.KRI_VALT_GD_C,'R','Red','G','Green','Y','Yellow') AS KRI_VALT_GD_C
  FROM SRBA_KRI_J_EXTR_M A
 WHERE A.BAS_YYMM=#{BAS_YYMM, jdbcType=VARCHAR}

