	UPDATE SRBA_IMPRV_POOL
	   SET IMPRV_CNFRME  	= #{IMPRV_CNFRME,jdbcType=VARCHAR}
		  ,MAIN_EXEC_CTNT   = #{MAIN_EXEC_CTNT,jdbcType=VARCHAR}
          ,ADD_INP_CTNT     = #{ADD_INP_CTNT,jdbcType=VARCHAR}
          ,CHG_DT 			= #{CHG_DT,jdbcType=VARCHAR}
          ,CHG_TIME 		= #{CHG_TIME,jdbcType=VARCHAR}
          ,CHG_OP_JKW_NO 	= #{CHG_OP_JKW_NO,jdbcType=VARCHAR}
	WHERE POOL_SNO = #{POOL_SNO}

mapper.select:
SELECT AA.BAS_YYMM ,AA.VALT_BRNO ,AA.DPRT_NM ,SUM(AA.TRGT_CNT ) AS TRGT_CNT , (SELECT COUNT(VALT_BRNO) FROM SRBA_IMPRV_M C WHERE C.BAS_YYMM = AA.BAS_YYMM AND C.VALT_BRNO = AA.VALT_BRNO AND C.GYLJ_S_C = '3' ) AS CMPT_CNT FROM ( SELECT A.BAS_YYMM ,A.VALT_BRNO , E.DPRT_NM AS DPRT_NM , COUNT(1) AS TRGT_CNT , NVL(B.GYLJ_S_C,'0') AS GYLJ_S_C , NVL(B.GYLJ_ID,'0') AS GYLJ_ID , NVL(B.IMPRV_CMPT_YN ,'0') AS IMPRV_CMPT_YN FROM SRBA_V_REMDR_R A LEFT OUTER JOIN SRBA_IMPRV_M B ON B.BAS_YYMM = A.BAS_YYMM AND B.PROC_FLD_C = A.PROC_FLD_C AND B.PROC_LGDV_C = A.PROC_LGDV_C AND B.PROC_MDDV_C = A.PROC_MDDV_C AND B.PROC_SMDV_C = A.PROC_SMDV_C AND B.VALT_BRNO = A.VALT_BRNO JOIN NIC41B E ON E.DPRT_CD = A.VALT_BRNO WHERE 1=1 AND REMDR_RSK_GD_C = 'R' AND A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} GROUP BY A.BAS_YYMM ,A.VALT_BRNO , E.DPRT_NM, B.GYLJ_S_C, B.GYLJ_ID, B.IMPRV_CMPT_YN ) AA WHERE 1=1
AND AA.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
AND AA.IMPRV_CMPT_YN = #{IMPRV_CMPT_YN, jdbcType=VARCHAR}
GROUP BY AA.BAS_YYMM, AA.VALT_BRNO,AA.DPRT_NM

SELECT * FROM ( SELECT A.BAS_YYMM , A.PROC_FLD_C , B.DTL_C_NM AS PROC_FLD_C_NM , A.PROC_LGDV_C , C.DTL_C_NM AS PROC_LGDV_C_NM , A.PROC_MDDV_C , D.DTL_C_NM AS PROC_MDDV_C_NM , A.PROC_SMDV_C , A.VALT_BRNO , E.DPRT_NM AS DPRT_NM ,( SELECT E.PROC_SMDV_NM FROM SRBA_V_PROC_M E WHERE E.BAS_YYMM = A.BAS_YYMM AND E.PROC_FLD_C = A.PROC_FLD_C AND E.PROC_LGDV_C = A.PROC_LGDV_C AND E.PROC_MDDV_C = A.PROC_MDDV_C AND E.PROC_SMDV_C = A.PROC_SMDV_C ) AS PROC_SMDV_NM , A.RSK_VALT_PNT , A.TONGJE_VALT_PNT , A.REMDR_RSK_PNT , A.REMDR_RSK_GD_C ,(SELECT DTL_C_NM FROM SRBA_DTL_C H WHERE H.GRP_C = 'R316' AND H.DTL_C = A.REMDR_RSK_GD_C) AS REMDR_RSK_GD_C_NM , NVL(G.IMPRV_CMPT_YN ,'0') AS IMPRV_CMPT_YN , G.IMPRV_BRNO , G.POOL_SNO , DECODE(G.IMPRV_CMPT_YN, '','미개선', (SELECT DTL_C_NM FROM SRBA_DTL_C H WHERE H.GRP_C = 'R326' AND H.DTL_C = TO_CHAR(G.IMPRV_CMPT_YN))) AS IMPRV_CMPT_YN_NM , NVL(G.GYLJ_S_C,'0') AS GYLJ_S_C , DECODE(G.GYLJ_S_C, '','미수행', (SELECT DTL_C_NM FROM SRBA_DTL_C H WHERE H.GRP_C = 'R325' AND H.DTL_C = G.GYLJ_S_C)) AS GYLJ_S_C_NM , G.GYLJ_DT , G.GYLJ_JKW_NO , GET_LOGINID_NAME(G.GYLJ_JKW_NO) AS GYLJ_JKW_NM , NVL(G.GYLJ_ID,'0') AS GYLJ_ID , G.GYLJ_ROLE_ID ,(SELECT ROLE_NM FROM C_ROLE K WHERE K.ROLE_ID = G.GYLJ_ROLE_ID ) AS GYLJ_ROLE_NM ,DECODE((SELECT AML_TJ_BRNO_YN FROM SRBA_VALT_BRNO WHERE BRNO = A.VALT_BRNO AND BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} ),'0','N','Y' ) AS TONJE_BRNO_YN FROM SRBA_V_REMDR_R A JOIN NIC41B E ON E.DPRT_CD = A.VALT_BRNO JOIN SRBA_DTL_C B ON B.DTL_C = A.PROC_FLD_C AND B.GRP_C = 'R303' JOIN SRBA_DTL_C C ON C.DTL_C = A.PROC_LGDV_C AND C.GRP_C = 'R304' JOIN SRBA_DTL_C D ON D.DTL_C = A.PROC_MDDV_C AND D.GRP_C = 'R305' LEFT OUTER JOIN SRBA_IMPRV_M G ON G.BAS_YYMM = A.BAS_YYMM AND G.PROC_FLD_C = A.PROC_FLD_C AND G.PROC_LGDV_C = A.PROC_LGDV_C AND G.PROC_MDDV_C = A.PROC_MDDV_C AND G.PROC_SMDV_C = A.PROC_SMDV_C AND G.VALT_BRNO = A.VALT_BRNO WHERE 1=1 AND A.REMDR_RSK_GD_C = 'R' AND A.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR} ) AA WHERE 1=1
AND AA.BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR}
AND AA.IMPRV_CMPT_YN = #{IMPRV_CMPT_YN, jdbcType=NUMERIC}
AND AA.GYLJ_S_C = #{GYLJ_S_C, jdbcType=VARCHAR}
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND (AA.GYLJ_S_C IS NULL OR AA.GYLJ_S_C IN ('0','11','22'))
AND (AA.GYLJ_ROLE_ID = #{ROLE_IDS, jdbcType=VARCHAR} OR ( AA.GYLJ_S_C IN ('0','11') AND AA.IMPRV_BRNO = #{BDPT_CD, jdbcType=VARCHAR}))
AND AA.GYLJ_ID <> 0 AND AA.GYLJ_ROLE_ID = #{ROLE_IDS, jdbcType=VARCHAR}
AND AA.VALT_BRNO = #{VALT_BRNO, jdbcType=VARCHAR} AND AA.GYLJ_ID <> 0 AND AA.GYLJ_ROLE_ID = #{ROLE_IDS, jdbcType=VARCHAR}

SELECT
      CC.REMDR_RSK_GD_C_NM AS REMDR_RSK_GD_C_NM3
FROM
(
SELECT
	   (SELECT DTL_C_NM
