      AND A.VALT_BRNO   = #{VALT_BRNO}

mapper.update:
MERGE INTO SRBA_IMPRV_M
			USING DUAL
		 ON (BAS_YYMM   = #{BAS_YYMM, jdbcType=VARCHAR}
		 AND PROC_FLD_C  = #{PROC_FLD_C, jdbcType=VARCHAR}
         AND PROC_LGDV_C = #{PROC_LGDV_C, jdbcType=VARCHAR}
         AND PROC_MDDV_C = #{PROC_MDDV_C, jdbcType=VARCHAR}
         AND PROC_SMDV_C = #{PROC_SMDV_C, jdbcType=VARCHAR}
         AND VALT_BRNO   = #{VALT_BRNO, jdbcType=VARCHAR}
         )
WHEN MATCHED THEN
	UPDATE SET
	   GYLJ_S_C          = #{GYLJ_S_C,jdbcType=VARCHAR}
	  ,IMPRV_STRG_CTNT   = #{IMPRV_STRG_CTNT,jdbcType=VARCHAR}
	  ,POOL_SNO          = #{POOL_SNO,jdbcType=VARCHAR}
	  ,IMPRV_RSLT_CTNT   = #{IMPRV_RSLT_CTNT,jdbcType=VARCHAR}
	  ,CHG_DT 			 = TO_CHAR(SYSDATE,'YYYYMMDD')
	  ,CHG_TIME 		 = TO_CHAR(SYSDATE,'HH24MISS')
	  ,CHG_OP_JKW_NO 	 = #{CHG_OP_JKW_NO,jdbcType=VARCHAR}
WHEN NOT MATCHED THEN
	INSERT
	(
	  BAS_YYMM
	, PROC_FLD_C
	, PROC_LGDV_C
	, PROC_MDDV_C
	, PROC_SMDV_C
	, VALT_BRNO
	, IMPRV_CMPT_YN
	, IMPRV_BRNO
	, IMPRV_STRG_CTNT
	, POOL_SNO
	, IMPRV_RSLT_CTNT
	, ATTCH_FILE_NO
	, GYLJ_ID
	, GYLJ_DT
	, GYLJ_S_C
	, GYLJ_JKW_NO
	, GYLJ_ROLE_ID
	, DR_DT
	, DR_TIME
	, DR_OP_JKW_NO
	, CHG_DT
	, CHG_TIME
	, CHG_OP_JKW_NO
	)
	VALUES
	(
	 #{BAS_YYMM, jdbcType=VARCHAR}
	,#{PROC_FLD_C, jdbcType=VARCHAR}
	,#{PROC_LGDV_C,jdbcType=VARCHAR}
	,#{PROC_MDDV_C,jdbcType=VARCHAR}
	,#{PROC_SMDV_C,jdbcType=VARCHAR}
	,#{VALT_BRNO,jdbcType=VARCHAR}
	,#{IMPRV_CMPT_YN,jdbcType=VARCHAR}
	,#{IMPRV_BRNO,jdbcType=VARCHAR}
	,#{IMPRV_STRG_CTNT,jdbcType=VARCHAR}
	,#{POOL_SNO,jdbcType=VARCHAR}
	,#{IMPRV_RSLT_CTNT,jdbcType=VARCHAR}
	,#{ATTCH_FILE_NO,jdbcType=VARCHAR}
	,#{GYLJ_ID,jdbcType=VARCHAR}
	,#{GYLJ_DT,jdbcType=VARCHAR}
	,#{GYLJ_S_C,jdbcType=VARCHAR}
	,#{GYLJ_JKW_NO,jdbcType=VARCHAR}
	,#{GYLJ_ROLE_ID,jdbcType=VARCHAR}
	,TO_CHAR(SYSDATE,'YYYYMMDD')
	,TO_CHAR(SYSDATE,'HH24MISS')
	,#{DR_OP_JKW_NO,jdbcType=VARCHAR}
	,TO_CHAR(SYSDATE,'YYYYMMDD')
	,TO_CHAR(SYSDATE,'HH24MISS')
	,#{CHG_OP_JKW_NO,jdbcType=VARCHAR}
	)

	UPDATE SRBA_IMPRV_M  A
	SET IMPRV_STRG_CTNT   = #{IMPRV_STRG_CTNT,jdbcType=VARCHAR}
	   ,POOL_SNO         = #{POOL_SNO,jdbcType=VARCHAR}
       ,IMPRV_RSLT_CTNT  = #{IMPRV_RSLT_CTNT,jdbcType=VARCHAR}
       ,CHG_DT 			 = TO_CHAR(SYSDATE,'YYYYMMDD')
       ,CHG_TIME 		 = TO_CHAR(SYSDATE,'HH24MISS')
       ,CHG_OP_JKW_NO 	 = #{CHG_OP_JKW_NO,jdbcType=VARCHAR}
	 WHERE A.BAS_YYMM    = #{BAS_YYMM}
       AND A.PROC_FLD_C  = #{PROC_FLD_C}
       AND A.PROC_LGDV_C = #{PROC_LGDV_C}
       AND A.PROC_MDDV_C = #{PROC_MDDV_C}
       AND A.PROC_SMDV_C = #{PROC_SMDV_C}
       AND A.VALT_BRNO   = #{VALT_BRNO}

	UPDATE SRBA_IMPRV_M  A
	SET IMPRV_CMPT_YN  	 = #{IMPRV_CMPT_YN,jdbcType=NUMERIC}
	   ,IMPRV_DT         = TO_CHAR(SYSDATE,'YYYYMMDD')
	   ,GYLJ_ID  	     = #{GYLJ_ID,jdbcType=VARCHAR}
	   ,GYLJ_DT          = TO_CHAR(SYSDATE,'YYYYMMDD')
       ,GYLJ_S_C         = #{GYLJ_S_C,jdbcType=VARCHAR}
	   ,GYLJ_JKW_NO      = #{GYLJ_JKW_NO,jdbcType=VARCHAR}
	   ,GYLJ_ROLE_ID     = CASE WHEN #{GYLJ_FLAG, jdbcType=VARCHAR} = '0' THEN
	                            (SELECT NEXT_GYLJ_ROLE_ID
                                 FROM C_GYLJ_D
                                 WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                   AND SNO           = 1)
                          WHEN #{GYLJ_FLAG, jdbcType=VARCHAR} = '1' THEN
                                (SELECT RTN_ROLE_ID
                                 FROM C_GYLJ_D
                                 WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                 AND GYLJ_ROLE_ID  = A.GYLJ_ROLE_ID
                                 AND GYLJ_ROLE_ID  = #{ROLE_ID, jdbcType=NUMERIC})
                          ELSE (SELECT NEXT_GYLJ_ROLE_ID
                               FROM C_GYLJ_D
                               WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                 AND GYLJ_ROLE_ID  = A.GYLJ_ROLE_ID
                                 AND GYLJ_ROLE_ID  = #{ROLE_ID, jdbcType=NUMERIC})
                           END
       ,CHG_DT 			 = TO_CHAR(SYSDATE,'YYYYMMDD')
       ,CHG_TIME 		 = TO_CHAR(SYSDATE,'HH24MISS')
       ,CHG_OP_JKW_NO 	 = #{CHG_OP_JKW_NO,jdbcType=VARCHAR}
	 WHERE A.BAS_YYMM    = #{BAS_YYMM}
       AND A.PROC_FLD_C  = #{PROC_FLD_C}
       AND A.PROC_LGDV_C = #{PROC_LGDV_C}
       AND A.PROC_MDDV_C = #{PROC_MDDV_C}
       AND A.PROC_SMDV_C = #{PROC_SMDV_C}
       AND A.VALT_BRNO   = #{VALT_BRNO}

