mapper.select:
SELECT C.RSK_CATG AS RSK_CATG , C.RSK_CATG_NM AS RSK_CATG_NM , C.RSK_FAC AS RSK_FAC , C.RSK_FAC_NM AS RSK_FAC_NM , C.RSK_INDCT AS RSK_INDCT , C.RSK_INDCT_NM AS RSK_INDCT_NM , NVL(D.KRI_CNT,0) AS KRI_CNT , C.KRI_NO AS KRI_NO FROM ( SELECT A.RSK_CATG AS RSK_CATG , ( SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R309' AND DTL_C= A.RSK_CATG ) AS RSK_CATG_NM , A.RSK_FAC AS RSK_FAC , ( SELECT DTL_C_NM AS NAME FROM SRBA_DTL_C WHERE USYN=1 AND GRP_C='R310' AND DTL_C= A.RSK_FAC ) AS RSK_FAC_NM , A.RSK_INDCT AS RSK_INDCT , A.RSK_INDCT_NM AS RSK_INDCT_NM , B.KRI_NO AS KRI_NO FROM SRBA_V_RSK_JIPYO_M A , SRBA_KRI_JIPYO_M B WHERE A.BAS_YYMM = (SELECT CASE WHEN (SELECT COUNT(*) FROM SRBA_VALT_SCHD_M) = 1 THEN '999912' ELSE (SELECT MAX(BAS_YYMM) FROM SRBA_VALT_SCHD_M WHERE BAS_YYMM NOT IN ('999912')) END AS BAS_YYMM FROM DUAL ) AND A.RSK_INDCT = B.REF_RSK_INDCT ) C LEFT OUTER JOIN ( SELECT KRI_NO AS KRI_NO , COUNT(*) AS KRI_CNT FROM SRBA_KRI_JR_MP GROUP BY KRI_NO ) D ON C.KRI_NO = D.KRI_NO WHERE 1=1
AND RSK_CATG = #{RSK_CATG, jdbcType=VARCHAR}
AND RSK_FAC = #{RSK_FAC, jdbcType=VARCHAR}
AND RSK_INDCT_NM LIKE '%' || #{RSK_INDCT_NM, jdbcType=VARCHAR} || '%'
ORDER BY KRI_NO

