MERGE INTO SRBA_RPT_M
USING DUAL
   ON (BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR})
 WHEN MATCHED THEN
      UPDATE SET R3_SUMMY 	= #{R3_SUMMY, jdbcType=VARCHAR}
      			,R7_TASK 	= #{R7_TASK, jdbcType=VARCHAR}
      			,R7_PLAN 	= #{R7_PLAN, jdbcType=VARCHAR}
      			,R7_DIREC 	= #{R7_DIREC, jdbcType=VARCHAR}
 WHEN NOT MATCHED THEN
      INSERT ( BAS_YYMM, R3_SUMMY, R7_TASK, R7_PLAN, R7_DIREC )
      VALUES ( #{BAS_YYMM, jdbcType=VARCHAR}, #{R3_SUMMY, jdbcType=VARCHAR}, #{R7_TASK, jdbcType=VARCHAR}, #{R7_PLAN, jdbcType=VARCHAR}, #{R7_DIREC, jdbcType=VARCHAR} )

mapper.select:
SELECT A.DTL_CD AS CD , A.DTL_NM AS CD_NM , A.GRP_CD AS GRP_CD FROM RBA030TB A , ( SELECT MAX(RPT_GJDT) AS RPT_GJDT FROM RBA030TB WHERE USYN = 1
AND GRP_CD = #{GRP_CD, jdbcType=VARCHAR}
) B WHERE A.USYN = 1
AND A.GRP_CD = #{GRP_CD, jdbcType=VARCHAR}
AND A.RPT_GJDT = B.RPT_GJDT ORDER BY A.DTL_CD

SELECT ROWNUM AS SEQ , D.RPRM_DT AS RPRM_DT , D.SNO AS SNO , D.RPRM_G_C AS RPRM_G_C , D.RPRM_G_NM AS RPRM_G_NM , D.RPRM_ACTN_G_C AS RPRM_ACTN_G_C , D.RPRM_ACTN_G_NM AS RPRM_ACTN_G_NM , D.RPRM_RSN AS RPRM_RSN , D.RPRM_TGT AS RPRM_TGT , D.LEV AS LEV , D.DR_DT AS DR_DT , D.DR_TIME AS DR_TIME , D.DR_OP_JKW_NO AS DR_OP_JKW_NO , D.DR_OP_JKW_NM AS DR_OP_JKW_NM , D.CHG_DT AS CHG_DT , D.CHG_TIME AS CHG_TIME , D.CHG_OP_JKW_NO AS CHG_OP_JKW_NO , D.CHG_OP_JKW_NM AS CHG_OP_JKW_NM , D.LOGIN_ID , D.DEP_ID , D.DEP_TITLE FROM ( SELECT A.RPRM_DT AS RPRM_DT , A.SNO AS SNO /* 순번 */ , A.RPRM_G_C AS RPRM_G_C /* 징계구분코드 */ , (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE DTL_C = A.RPRM_G_C AND GRP_C = 'R351') AS RPRM_G_NM , A.RPRM_ACTN_G_C AS RPRM_ACTN_G_C /* 징계조치구분코드 */ , DECODE(RPRM_G_C, '1', (SELECT B.DTL_NM FROM RBA030TB B , ( SELECT MAX(RPT_GJDT) AS RPT_GJDT FROM RBA030TB WHERE GRP_CD = 'C0001' AND USYN = 1 ) C WHERE B.GRP_CD = 'C0001' AND B.RPT_GJDT =C.RPT_GJDT AND B.DTL_CD = A.RPRM_ACTN_G_C), 2, (SELECT B.DTL_NM FROM RBA030TB B , ( SELECT MAX(RPT_GJDT) AS RPT_GJDT FROM RBA030TB WHERE GRP_CD = 'C0002' AND USYN = 1 ) C WHERE B.GRP_CD = 'C0002' AND B.RPT_GJDT =C.RPT_GJDT AND B.DTL_CD = A.RPRM_ACTN_G_C), '' ) AS RPRM_ACTN_G_NM , A.RPRM_RSN AS RPRM_RSN /* 징계사유 */ , A.RPRM_TGT AS RPRM_TGT /* 징계대상 */ , A.LEV AS LEV /* 직급 */ , A.DR_DT AS DR_DT /* 등록일자 */ , A.DR_TIME AS DR_TIME /* 등록시간 */ , A.DR_OP_JKW_NO AS DR_OP_JKW_NO /* 등록조작자번호 */ , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.DR_OP_JKW_NO) AS DR_OP_JKW_NM , A.CHG_DT AS CHG_DT /* 변경일자 */ , A.CHG_TIME AS CHG_TIME /* 변경시간 */ , A.CHG_OP_JKW_NO AS CHG_OP_JKW_NO /* 변경조작자번호 */ , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.CHG_OP_JKW_NO) AS CHG_OP_JKW_NM , A.LOGIN_ID , A.DEP_ID , A.DEP_TITLE FROM SRBA_OUT_RPRM_M A WHERE A.RPRM_DT BETWEEN #{stDate, jdbcType=VARCHAR} AND #{edDate, jdbcType=VARCHAR}
AND A.RPRM_G_C = #{RPRM_G_C, jdbcType=VARCHAR}
AND A.RPRM_ACTN_G_C = #{RPRM_ACTN_G_C, jdbcType=VARCHAR}
ORDER BY A.RPRM_DT DESC, A.SNO DESC ) D

SELECT NVL(MAX(SNO),0) + 1 AS SNO
FROM SRBA_OUT_RPRM_M
WHERE RPRM_DT = #{RPRM_DT, jdbcType=VARCHAR}

