SELECT ROWNUM AS SEQ , D.DCS_DT AS DCS_DT , D.SNO AS SNO , D.DOC_TITE AS DOC_TITE , D.DCS_RQST_BRNO AS DCS_RQST_BRNO , (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R352' AND DTL_C = D.DCS_RQST_BRNO) AS DCS_RQST_BRNM , D.RSLT_ATTCH_FILE_NO AS RSLT_ATTCH_FILE_NO , DECODE(D.RSLT_CNT, 0, 'N', 'Y') AS RSLT_ATTCH_FILE_YN , D.RPT_G_C AS RPT_G_C , D.RPT_G_NM AS RPT_G_NM , D.RSLT_G_C AS RSLT_G_C , D.RSLT_G_NM AS RSLT_G_NM , D.NOTE_CTNT AS NOTE_CTNT , D.ACTN_PLAN_YN AS ACTN_PLAN_YN , D.ACT_PRGR_S_C AS ACT_PRGR_S_C , D.ACTN_PLAN_TITE AS ACTN_PLAN_TITE , D.DP_SEND_DT AS DP_SEND_DT , D.ACTN_PLAN_CTNT AS ACTN_PLAN_CTNT , D.ACTN_ATTCH_FILE_NO AS ACTN_ATTCH_FILE_NO , DECODE(D.ACTN_CNT, 0, 'N', 'Y') AS ACTN_ATTCH_FILE_YN , D.ACTN_DT AS ACTN_DT , D.ACTN_PLAN_G_C AS ACTN_PLAN_G_C , D.DR_DT AS DR_DT /* 등록일자 */ , D.DR_TIME AS DR_TIME /* 등록시간 */ , D.DR_OP_JKW_NO AS DR_OP_JKW_NO /* 등록조작자번호 */ , D.DR_OP_JKW_NM AS DR_OP_JKW_NM , D.CHG_DT AS CHG_DT , D.CHG_TIME AS CHG_TIME , D.CHG_OP_JKW_NO AS CHG_OP_JKW_NO , D.CHG_OP_JKW_NM AS CHG_OP_JKW_NM , D.BRNM AS BRNM --유안타증권 BSL FROM ( SELECT A.DCS_DT AS DCS_DT , A.SNO AS SNO , A.DOC_TITE AS DOC_TITE , A.DCS_RQST_BRNO AS DCS_RQST_BRNO , A.RSLT_ATTCH_FILE_NO AS RSLT_ATTCH_FILE_NO , ( SELECT COUNT(*) FROM RBA_ATTCH_FILE WHERE ATTCH_FILE_NO = A.RSLT_ATTCH_FILE_NO ) AS RSLT_CNT , A.RPT_G_C AS RPT_G_C , ( SELECT B.DTL_NM FROM RBA030TB B , ( SELECT MAX(RPT_GJDT) AS RPT_GJDT FROM RBA030TB WHERE GRP_CD = 'C0003' AND USYN = 1 ) C WHERE B.USYN = 1 AND B.RPT_GJDT = C.RPT_GJDT AND B.GRP_CD = 'C0003' AND B.DTL_CD = A.RPT_G_C ) AS RPT_G_NM , A.RSLT_G_C AS RSLT_G_C , ( SELECT B.DTL_NM FROM RBA030TB B , ( SELECT MAX(RPT_GJDT) AS RPT_GJDT FROM RBA030TB WHERE GRP_CD = 'C0045' AND USYN = 1 ) C WHERE B.USYN = 1 AND B.RPT_GJDT = C.RPT_GJDT AND B.GRP_CD = 'C0045' AND B.DTL_CD = A.RSLT_G_C ) AS RSLT_G_NM , A.NOTE_CTNT AS NOTE_CTNT , A.ACTN_PLAN_YN AS ACTN_PLAN_YN , A.ACT_PRGR_S_C AS ACT_PRGR_S_C , A.ACTN_PLAN_TITE AS ACTN_PLAN_TITE , A.DP_SEND_DT AS DP_SEND_DT , A.ACTN_PLAN_CTNT AS ACTN_PLAN_CTNT , A.ACTN_ATTCH_FILE_NO AS ACTN_ATTCH_FILE_NO , ( SELECT COUNT(*) FROM RBA_ATTCH_FILE WHERE ATTCH_FILE_NO = A.ACTN_ATTCH_FILE_NO ) AS ACTN_CNT , A.ACTN_DT AS ACTN_DT , A.ACTN_PLAN_G_C AS ACTN_PLAN_G_C , A.DR_DT AS DR_DT /* 등록일자 */ , A.DR_TIME AS DR_TIME /* 등록시간 */ , A.DR_OP_JKW_NO AS DR_OP_JKW_NO /* 등록조작자번호 */ , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.DR_OP_JKW_NO) AS DR_OP_JKW_NM , A.CHG_DT AS CHG_DT , A.CHG_TIME AS CHG_TIME , A.CHG_OP_JKW_NO AS CHG_OP_JKW_NO , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.CHG_OP_JKW_NO) AS CHG_OP_JKW_NM , ( SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.BRNO ) AS BRNM -- 유안타증권 - 추가 FROM SRBA_AML_ACTRPT_M A WHERE A.DCS_DT BETWEEN #{stDate, jdbcType=VARCHAR} AND #{edDate, jdbcType=VARCHAR}
AND A.RPT_G_C = #{RPT_G_C, jdbcType=VARCHAR}
AND A.RSLT_G_C = #{RSLT_G_C, jdbcType=VARCHAR}
AND A.DOC_TITE LIKE '%' || #{DOC_TITE, jdbcType=VARCHAR} || '%'
AND A.DCS_RQST_BRNO = #{DCS_RQST_BRNO, jdbcType=VARCHAR}
ORDER BY A.DCS_DT DESC, A.SNO DESC ) D

