SELECT ROWNUM AS SEQ , D.EDU_DT AS EDU_DT , D.SNO AS SNO , D.EDU_CHNL_G_NM AS EDU_CHNL_G_NM , D.EDU_CHNL_G_C AS EDU_CHNL_G_C , D.EDU_MAIN_BRNO AS EDU_MAIN_BRNO , D.EDU_MAIN_BRNM AS EDU_MAIN_BRNM , D.EDU_TGT_G_NM AS EDU_TGT_G_NM , D.EDU_TGT_G_C AS EDU_TGT_G_C , D.EDU_SUBJ_NM AS EDU_SUBJ_NM , D.EDU_PGM_C AS EDU_PGM_C , D.EDU_SDT AS EDU_SDT , D.EDU_EDT AS EDU_EDT , D.EDU_HOUR AS EDU_HOUR , D.EDU_TGT_PCNT AS EDU_TGT_PCNT , D.FNSH_PCNT AS FNSH_PCNT , D.ATTCH_FILE_NO AS ATTCH_FILE_NO , DECODE( D.ATTCH_CNT, 0, 'N', 'Y' ) AS ATTCH_FILE_YN , D.EDU_JKW_NM AS EDU_JKW_NM , D.DR_DT AS DR_DT /* 등록일자 */ , D.DR_TIME AS DR_TIME /* 등록시간 */ , D.DR_OP_JKW_NO AS DR_OP_JKW_NO , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = D.DR_OP_JKW_NO) AS DR_OP_JKW_NM , D.CHG_DT AS CHG_DT , D.CHG_TIME AS CHG_TIME , D.CHG_OP_JKW_NO AS CHG_OP_JKW_NO , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = D.CHG_OP_JKW_NO) AS CHG_OP_JKW_NM FROM ( SELECT A.EDU_DT AS EDU_DT , A.SNO AS SNO , A.EDU_SUBJ_NM AS EDU_SUBJ_NM , A.EDU_TGT_G_C AS EDU_TGT_G_C , ( SELECT B.DTL_NM FROM RBA030TB B , ( SELECT MAX(RPT_GJDT) AS RPT_GJDT FROM RBA030TB WHERE GRP_CD = 'C0004' AND USYN = 1 ) C WHERE B.USYN = 1 AND B.RPT_GJDT = C.RPT_GJDT AND B.GRP_CD = 'C0004' AND B.DTL_CD = A.EDU_TGT_G_C ) AS EDU_TGT_G_NM , A.EDU_CHNL_G_C AS EDU_CHNL_G_C , ( SELECT B.DTL_NM FROM RBA030TB B , ( SELECT MAX(RPT_GJDT) AS RPT_GJDT FROM RBA030TB WHERE GRP_CD = 'C0006' AND USYN = 1 ) C WHERE B.USYN = 1 AND B.RPT_GJDT = C.RPT_GJDT AND B.GRP_CD = 'C0006' AND B.DTL_CD = A.EDU_CHNL_G_C ) AS EDU_CHNL_G_NM , A.EDU_SDT AS EDU_SDT , A.EDU_EDT AS EDU_EDT , A.ATTCH_FILE_NO AS ATTCH_FILE_NO , ( SELECT COUNT(*) FROM RBA_ATTCH_FILE WHERE ATTCH_FILE_NO = A.ATTCH_FILE_NO ) AS ATTCH_CNT , A.EDU_PGM_C AS EDU_PGM_C , A.EDU_MAIN_BRNO AS EDU_MAIN_BRNO , ( SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.EDU_MAIN_BRNO ) AS EDU_MAIN_BRNM , A.EDU_HOUR AS EDU_HOUR , A.EDU_JKW_NM AS EDU_JKW_NM , A.EDU_TGT_PCNT AS EDU_TGT_PCNT , A.FNSH_PCNT AS FNSH_PCNT , A.DR_DT AS DR_DT /* 등록일자 */ , A.DR_TIME AS DR_TIME /* 등록시간 */ , A.DR_OP_JKW_NO AS DR_OP_JKW_NO /* 등록조작자번호 */ , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.DR_OP_JKW_NO) AS DR_OP_JKW_NM , A.CHG_DT AS CHG_DT , A.CHG_TIME AS CHG_TIME , A.CHG_OP_JKW_NO AS CHG_OP_JKW_NO , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.CHG_OP_JKW_NO) AS CHG_OP_JKW_NM FROM SRBA_EDU_SCHD_M A WHERE A.EDU_DT BETWEEN #{stDate, jdbcType=VARCHAR} AND #{edDate, jdbcType=VARCHAR}
AND A.EDU_TGT_G_C = #{EDU_TGT_G_C, jdbcType=VARCHAR}
