SELECT ROWNUM AS SEQ , D.ISPT_DT AS ISPT_DT , D.SNO AS SNO , D.BRNO_G_C AS BRNO_G_C , D.BRNO_G_NM AS BRNO_G_NM , D.BRNO AS BRNO , D.BRNM AS BRNM , D.IMPRV_G_NM AS IMPRV_G_NM , D.IMPRV_G_C AS IMPRV_G_C , D.INDI_CNT AS INDI_CNT , D.IMPRV_RSK_GD_NM AS IMPRV_RSK_GD_NM , D.IMPRV_RSK_GD_C AS IMPRV_RSK_GD_C , D.ACTN_DT AS ACTN_DT , D.MAIN_ISPT_CTNT AS MAIN_ISPT_CTNT , D.MAIN_INDI_ITM AS MAIN_INDI_ITM , D.ACTN_DTL AS ACTN_DTL , D.DR_DT AS DR_DT , D.DR_TIME AS DR_TIME , D.DR_OP_JKW_NO AS DR_OP_JKW_NO , D.DR_OP_JKW_NM AS DR_OP_JKW_NM , D.CHG_DT AS CHG_DT , D.CHG_TIME AS CHG_TIME , D.CHG_OP_JKW_NO AS CHG_OP_JKW_NO , D.CHG_OP_JKW_NM AS CHG_OP_JKW_NM FROM ( SELECT A.ISPT_DT AS ISPT_DT , A.SNO AS SNO /* 순번 */ , A.BRNO_G_C AS BRNO_G_C /* 영업점구분코드 */ , ( SELECT B.DTL_NM FROM RBA030TB B , ( SELECT MAX(RPT_GJDT) AS RPT_GJDT FROM RBA030TB WHERE GRP_CD = 'C0013' AND USYN = 1 ) C WHERE B.GRP_CD = 'C0013' AND B.RPT_GJDT =C.RPT_GJDT AND B.DTL_CD = A.BRNO_G_C ) AS BRNO_G_NM , A.BRNO AS BRNO , ( SELECT DPRT_NM FROM NIC41B WHERE DPRT_CD = A.BRNO ) AS BRNM , ( SELECT B.DTL_NM FROM RBA030TB B , ( SELECT MAX(RPT_GJDT) AS RPT_GJDT FROM RBA030TB WHERE GRP_CD = 'C0048' AND USYN = 1 ) C WHERE B.GRP_CD = 'C0048' AND B.RPT_GJDT =C.RPT_GJDT AND B.DTL_CD = A.IMPRV_G_C) AS IMPRV_G_NM , A.IMPRV_G_C AS IMPRV_G_C /* 개선구분코드 */ , A.INDI_CNT AS INDI_CNT /* 지적건수 */ , ( SELECT B.DTL_NM FROM RBA030TB B , ( SELECT MAX(RPT_GJDT) AS RPT_GJDT FROM RBA030TB WHERE GRP_CD = 'C0014' AND USYN = 1 ) C WHERE B.GRP_CD = 'C0014' AND B.RPT_GJDT =C.RPT_GJDT AND B.DTL_CD = A.IMPRV_RSK_GD_C) AS IMPRV_RSK_GD_NM , A.IMPRV_RSK_GD_C AS IMPRV_RSK_GD_C /* 위험등급코드 */ , A.ACTN_DT AS ACTN_DT /* 조치일자 */ , A.MAIN_ISPT_CTNT AS MAIN_ISPT_CTNT /* 주요점검내용 */ , A.MAIN_INDI_ITM AS MAIN_INDI_ITM /* 주요지적사항 */ , A.ACTN_DTL AS ACTN_DTL /* 조치내역 */ , A.DR_DT AS DR_DT /* 등록일자 */ , A.DR_TIME AS DR_TIME /* 등록시간 */ , A.DR_OP_JKW_NO AS DR_OP_JKW_NO /* 등록조작자번호 */ , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.DR_OP_JKW_NO) AS DR_OP_JKW_NM , A.CHG_DT AS CHG_DT /* 변경일자 */ , A.CHG_TIME AS CHG_TIME /* 변경시간 */ , A.CHG_OP_JKW_NO AS CHG_OP_JKW_NO /* 변경조작자번호 */ , (SELECT USER_NM FROM C_USER WHERE LOGIN_ID = A.CHG_OP_JKW_NO) AS CHG_OP_JKW_NM FROM SRBA_BRNO_ISPT_M A WHERE A.ISPT_DT BETWEEN #{stDate, jdbcType=VARCHAR} AND #{edDate, jdbcType=VARCHAR}
AND A.BRNO_G_C = #{BRNO_G_C, jdbcType=VARCHAR}
AND A.IMPRV_G_C = #{IMPRV_G_C, jdbcType=VARCHAR}
