SELECT ROWNUM AS NUM,A.* FROM ( SELECT BAS_YYYYMM , ACD_OCC_G_C ,(SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R328' AND DTL_C = ACD_OCC_G_C) AS ACD_OCC_G_C_NM , ACD_OCC_AMT , DR_DT , DR_OP_JKW_NO ,(SELECT USER_NM FROM C_USER WHERE LOGIN_ID = DR_OP_JKW_NO) AS DR_OP_JKW_NM FROM SRBA_FNN_ACD_M WHERE BAS_YYYYMM BETWEEN #{startDate, jdbcType=VARCHAR} AND #{endDate, jdbcType=VARCHAR}
AND ACD_OCC_G_C = #{ACD_OCC_G_C, jdbcType=VARCHAR}
ORDER BY BAS_YYYYMM DESC ) A

