SELECT RBA_BTCH_DT --RBA배치일자 , BAS_YYMM --기준년월 , ING_STEP --진행단계 , (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R327' AND DTL_C = ING_STEP) AS ING_STEP_NM , RBA_BTCH_SDT --RBA배치시작일자 , RBA_BTCH_EDT --RBA배치종료일자 , RBA_BTCH_S_C --RBA배치상태코드 , (SELECT DTL_C_NM FROM SRBA_DTL_C WHERE GRP_C = 'R400' AND DTL_C = RBA_BTCH_S_C) AS RBA_BTCH_S_C_NM , ERR_CTNT --오류내용 , DR_DT --등록일자 , DR_TIME --등록시간 FROM SRBA_V_BTCH_H WHERE 1=1 AND SUBSTR(RBA_BTCH_DT,0,8) BETWEEN #{startDate, jdbcType=VARCHAR} AND #{endDate, jdbcType=VARCHAR}
AND BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
ORDER BY RBA_BTCH_DT DESC

