mapper.update:
MERGE INTO SRBA_RPT_IMPRV_I
USING DUAL
   ON (BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR})
 WHEN MATCHED THEN
      UPDATE SET IMPRV_RSLT_CTNT   = #{IMPRV_RSLT_CTNT, jdbcType=VARCHAR}
      			,CHG_DT 	       = TO_CHAR(SYSDATE , 'YYYYMMDD')
      			,CHG_TIME 	       = TO_CHAR(SYSDATE , 'HH24MISS')
      			,CHG_OP_JKW_NO     = #{OP_JKW_NO, jdbcType=VARCHAR}
 WHEN NOT MATCHED THEN
      INSERT ( BAS_YYMM, IMPRV_RSLT_CTNT, DR_DT, DR_TIME, DR_OP_JKW_NO )
      VALUES (
               #{BAS_YYMM, jdbcType=VARCHAR}
             , #{IMPRV_RSLT_CTNT, jdbcType=VARCHAR}
             , TO_CHAR(SYSDATE , 'YYYYMMDD')
             , TO_CHAR(SYSDATE , 'HH24MISS')
             , #{OP_JKW_NO, jdbcType=VARCHAR}
             )

UPDATE SRBA_RPT_IMPRV_I
	SET
	      FILE_POS				= #{FILE_POS, jdbcType=VARCHAR}
	    , FILE_NAME			 	= #{FILE_NAME, jdbcType=VARCHAR}
	 WHERE
	 		BAS_YYMM	= #{BAS_YYMM, jdbcType=VARCHAR}

UPDATE SRBA_V_TONGJE_M
   SET
      ATTCH_FILE_NO  	 = #{ATTCH_FILE_NO,jdbcType=VARCHAR},
   	  CHG_DT             = TO_CHAR(SYSDATE,'YYYYMMDD'),
	  CHG_TIME           = TO_CHAR(SYSDATE,'HH24MISS'),
	  CHG_OP_JKW_NO      = #{DR_OP_JKW_NO, jdbcType=VARCHAR}
WHERE BAS_YYMM = #{BAS_YYMM, jdbcType=VARCHAR}
  AND PROC_SMDV_C = #{PROC_SMDV_C, jdbcType=VARCHAR}
  AND TONGJE_NO = #{TONGJE_NO, jdbcType=VARCHAR}

UPDATE SRBA_V_HRSK_R  A SET
	GYLJ_ID  	     = #{GYLJ_ID,jdbcType=VARCHAR}
  , GYLJ_S_C         = #{GYLJ_S_C,jdbcType=VARCHAR}
  , GYLJ_ROLE_ID     = CASE WHEN #{GYLJ_FLAG, jdbcType=VARCHAR} = '0' THEN
                           		(SELECT NEXT_GYLJ_ROLE_ID
                                 FROM C_GYLJ_D
                                 WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                   AND SNO           = 1)
                        	WHEN #{GYLJ_FLAG, jdbcType=VARCHAR} = '1' THEN
                                (SELECT RTN_ROLE_ID
                                 FROM C_GYLJ_D
                                 WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                   AND GYLJ_ROLE_ID  = A.GYLJ_ROLE_ID
                                   AND GYLJ_ROLE_ID  = #{ROLE_ID, jdbcType=NUMERIC})
                        	ELSE (SELECT NEXT_GYLJ_ROLE_ID
                                  FROM C_GYLJ_D
                                  WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                    AND GYLJ_ROLE_ID  = A.GYLJ_ROLE_ID
                                    AND GYLJ_ROLE_ID  = #{ROLE_ID, jdbcType=NUMERIC})
                         	END
WHERE A.BAS_YYMM    = #{BAS_YYMM}
  AND A.VALT_BRNO   = #{VALT_BRNO}

UPDATE SRBA_V_TONGJE_R A SET
	GYLJ_ID  	     = #{GYLJ_ID,jdbcType=VARCHAR}
  , GYLJ_S_C         = #{GYLJ_S_C,jdbcType=VARCHAR}
  , GYLJ_ROLE_ID     = CASE WHEN #{GYLJ_FLAG, jdbcType=VARCHAR} = '0' THEN
                           		(SELECT NEXT_GYLJ_ROLE_ID
                                 FROM C_GYLJ_D
                                 WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                   AND SNO           = 1)
                        	WHEN #{GYLJ_FLAG, jdbcType=VARCHAR} = '1' THEN
                                (SELECT RTN_ROLE_ID
                                 FROM C_GYLJ_D
                                 WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                   AND GYLJ_ROLE_ID  = A.GYLJ_ROLE_ID
                                   AND GYLJ_ROLE_ID  = #{ROLE_ID, jdbcType=NUMERIC})
                        	ELSE (SELECT NEXT_GYLJ_ROLE_ID
                                  FROM C_GYLJ_D
                                  WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C, jdbcType=VARCHAR}
                                    AND GYLJ_ROLE_ID  = A.GYLJ_ROLE_ID
                                    AND GYLJ_ROLE_ID  = #{ROLE_ID, jdbcType=NUMERIC})
                         	END
WHERE A.BAS_YYMM    = #{BAS_YYMM}
  AND A.VALT_BRNO   = #{VALT_BRNO}

